// Initialize perpetual rain drops for Song of Rain overlay
document.addEventListener('DOMContentLoaded', () => {
  const $overlay = document.getElementById('rain-overlay');
  if (!$overlay) return;
  for (let i = 0; i < 80; i++) {
    const $d = document.createElement('div');
    $d.className = 'rain-drop';
    $d.style.left   = (Math.random() * 102) + 'vw';
    $d.style.height = (10 + Math.random() * 20) + 'px';
    $d.style.animationDuration = (0.5 + Math.random() * 0.8) + 's';
    $d.style.animationDelay   = -(Math.random() * 1.5) + 's';
    $overlay.appendChild($d);
  }
});

// ═══════════════════════════════════════════════════════════════════════════
//  MAGIC MODIFIER MODE (selecting cards to discard for spell cost override)
// ═══════════════════════════════════════════════════════════════════════════
let magicModifierMode = null; // { selectedIndices: Set }

function enterMagicModifierMode() {
  magicModifierMode = { selectedIndices: new Set() };
  rerenderHand();
  updateButtons();
}

function exitMagicModifierMode() {
  magicModifierMode = null;
  rerenderHand();
  updateButtons();
}

function toggleMagicModifierCard(idx) {
  if (!magicModifierMode) return;
  if (magicModifierMode.selectedIndices.has(idx)) {
    magicModifierMode.selectedIndices.delete(idx);
  } else {
    magicModifierMode.selectedIndices.add(idx);
  }
  rerenderHand();
  updateButtons();
}

function confirmMagicModifier() {
  if (!magicModifierMode) return;
  emit('magicModifier:confirm', {
    discardIndices: [...magicModifierMode.selectedIndices],
  });
  magicModifierMode = null;
  rerenderHand();
  updateButtons();
}

function enterDiscardMode(cardIndex, cost, maxCost) {
  // Dynamic cap for variable-cost cards based on board state
  if (cost === -1 && maxCost && lastState) {
    const card = lastState.you.hand[cardIndex];
    if (card && card.name === 'Book of Doom') {
      const targets = countBoardTargets(lastState);
      maxCost = Math.min(maxCost, targets);
      if (maxCost < 1) maxCost = 1;
    }
    if (card && card.name === 'Frost Breaker') {
      const tapped = countTappedTargetsClient(lastState);
      maxCost = Math.max(0, tapped - 1);
    }
    if (card && card.name === 'Smug Coin') {
      const discardSize = (lastState.you.discardPile || []).length;
      maxCost = Math.min(maxCost || discardSize, discardSize);
      if (maxCost < 1) maxCost = 1;
    }
  }
  const card = lastState?.you?.hand?.[cardIndex];
  const minCost = (card && card.minCost !== undefined) ? card.minCost : 1;
  discardMode = { cardIndex, cost, maxCost: maxCost ?? null, minCost, selectedPayment: new Set() };
  emit('game:consideringCard', { cardIndex });
  rerenderHand();
  updateButtons();
  if (lastState) renderMyBoard(lastState);
}

function countBoardTargets(state) {
  let count = 0;
  const you = state.you;
  if (you.chosenStudent && !you.studentDead) count++;
  for (const f of (you.familiars || [])) {
    if ((f.currentHp || 0) > 0) count++;
  }
  for (const opp of (state.others || [])) {
    if (opp.chosenStudent && !opp.studentDead) count++;
    for (const f of (opp.familiars || [])) {
      if ((f.currentHp || 0) > 0) count++;
    }
  }
  return count;
}

function countTappedTargetsClient(state) {
  let count = 0;
  const you = state.you;
  if (you.chosenStudent && !you.studentDead && you.tappedStudent) count++;
  if (!you.classPetImmunity) {
    for (let i = 0; i < (you.familiars || []).length; i++) {
      if (you.familiars[i] && (you.familiars[i].currentHp || 0) > 0 && !you.familiars[i].mechImmune && (you.tappedFamiliars || []).includes(i)) count++;
    }
  }
  for (const opp of (state.others || [])) {
    if (opp.chosenStudent && !opp.studentDead && opp.tappedStudent) count++;
    if (!opp.classPetImmunity) {
      for (let i = 0; i < (opp.familiars || []).length; i++) {
        if (opp.familiars[i] && (opp.familiars[i].currentHp || 0) > 0 && !opp.familiars[i].mechImmune && (opp.tappedFamiliars || []).includes(i)) count++;
      }
    }
  }
  return count;
}

/**
 * Check if a specific opponent target is blocked by taunting for the current player.
 * Returns true if the target CANNOT be selected because a viable taunting target exists.
 * @param {object} opp - opponent data from state.others
 * @param {string} myId - current player's ID
 * @param {string} targetType - 'student' or 'familiar'
 * @param {number} familiarIndex - only for familiar targets
 * @param {object} options - { familiarsOnly, tappedOnly, untappedOnly, sourceType, noSummoned }
 */
function isTauntBlockedClient(opp, myId, targetType, familiarIndex, options = {}) {
  if (!opp || opp.id === myId) return false; // self-targeting: never blocked

  // If this target is taunting, it's always allowed
  if (targetType === 'student' && (opp.chosenStudent?.taunting || 0) > 0) return false;
  if (targetType === 'familiar') {
    const fam = opp.familiars?.[familiarIndex];
    if (fam && (fam.taunting || 0) > 0) return false;
  }

  const tappedFams = opp.tappedFamiliars || [];

  // Check if any viable taunting target exists for this opponent
  // Student
  if (!options.familiarsOnly && opp.chosenStudent && !opp.studentDead && (opp.chosenStudent.taunting || 0) > 0) {
    let viable = true;
    if (options.tappedOnly && !opp.tappedStudent) viable = false;
    if (options.untappedOnly && opp.tappedStudent) viable = false;
    if (options.sourceType === 'familiar' && opp.shyGirlImmune) viable = false;
    if (viable) return true;
  }
  // Familiars
  for (let i = 0; i < (opp.familiars || []).length; i++) {
    const f = opp.familiars[i];
    if (!f || f.currentHp <= 0 || (f.taunting || 0) <= 0) continue;
    let viable = true;
    if (options.tappedOnly && !tappedFams.includes(i)) viable = false;
    if (options.untappedOnly && tappedFams.includes(i)) viable = false;
    if (options.noSummoned && f.summoned) viable = false;
    if (viable) return true;
  }

  return false; // no viable taunting targets — non-taunting is allowed
}

/**
 * Check if any target on the board has poison stacks.
 */
function hasPoisonedTargetOnBoard(state) {
  const you = state.you;
  if (you.chosenStudent && !you.studentDead && (you.chosenStudent.poisonStacks || 0) > 0) return true;
  for (const f of (you.familiars || [])) {
    if ((f.currentHp || 0) > 0 && (f.poisonStacks || 0) > 0) return true;
  }
  for (const opp of (state.others || [])) {
    if (opp.chosenStudent && !opp.studentDead && (opp.chosenStudent.poisonStacks || 0) > 0) return true;
    for (const f of (opp.familiars || [])) {
      if ((f.currentHp || 0) > 0 && (f.poisonStacks || 0) > 0) return true;
    }
  }
  return false;
}

// Action Figures: grayed out if no alive non-summoned non-copier familiar exists on any board
const ACTION_FIGURES_COPIERS = new Set(['Skeleton Bard', 'Clone', 'Golden Hind']);
function hasEligibleFamiliarOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    for (const f of (p.familiars || [])) {
      if ((f.currentHp || 0) > 0 && !f.summoned && !ACTION_FIGURES_COPIERS.has(f.name) && !f.isClone) return true;
    }
  }
  return false;
}

function hasTappedTargetOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if (p.tappedStudent && p.chosenStudent && !p.studentDead && !p.won && !p.studentPetrified) return true;
    for (let i = 0; i < (p.familiars || []).length; i++) {
      const f = p.familiars[i];
      if (f && f.currentHp > 0 && !f.petrified && !f.mechImmune && (p.tappedFamiliars || []).includes(i)) return true;
    }
  }
  return false;
}

function countBottledLightningTargetsForOpponent(opp) {
  let count = 0;
  if (opp.chosenStudent && !opp.studentDead && !opp.won && !opp.angelwingBackpack) count++;
  for (const f of (opp.familiars || [])) {
    if (f && f.currentHp > 0 && !f.goldenHindImmune) count++;
  }
  return count;
}

function hasOpponentWith2EligibleTargets(state) {
  for (const opp of (state.others || [])) {
    if (countBottledLightningTargetsForOpponent(opp) >= 2) return true;
  }
  return false;
}

function hasLivingFamiliarOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    for (const f of (p.familiars || [])) {
      if (f && f.currentHp > 0 && !f.summoned) return true;
    }
  }
  return false;
}

function hasItemInAnyDiscard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    for (const c of (p.discardPile || [])) {
      if (c && c.type === 'Item' && c.name !== 'Copy Device') return true;
    }
  }
  return false;
}

function hasEquipInAnyDiscard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if (p.left) continue;
    for (const c of (p.discardPile || [])) {
      if (c && c.type === 'Equip') return true;
    }
  }
  return false;
}

function hasGoldenAppleEligibleOpponent(state) {
  for (const opp of (state.others || [])) {
    if (opp.left || opp.won || opp.studentDead) continue;
    if (opp.chosenStudent && !opp.studentDead) return true;
  }
  return false;
}

function hasAnyDiscardCard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if ((p.discardPile || []).length > 0) return true;
  }
  return false;
}

function hasAnySnareOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if ((p.snares || []).length > 0) return true;
  }
  return false;
}

function hasAnyEquipOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if ((p.equips || []).length > 0) return true;
  }
  return false;
}

function hasAnyFieldSpellOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if ((p.fieldSpells || []).length > 0) return true;
  }
  return false;
}

function hasAnyLivingFamiliarOnBoard(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if ((p.familiars || []).some(f => f && f.currentHp > 0)) return true;
  }
  return false;
}

function hasAnyEligibleMysteryBoxSpell(state) {
  // Mirror the server's getMysteryBoxEligibleSpells basic filters:
  // - must be a Spell
  // - not vanilla (no effect listed in effect text — heuristic: no spellEffect data on card)
  // - not a field spell
  // - not variable cost (cost !== -1)
  // Client can't run isSpellCastable, so rare false positives are acceptable.
  // But we must at least exclude vanilla/field/variable so common "no spells" case grays correctly.
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    for (const c of (p.discardPile || [])) {
      if (c.type !== 'Spell') continue;
      if (c.vanilla) continue;
      if (c.fieldSpell) continue;
      if ((c.cost ?? 0) === -1) continue;
      return true;
    }
  }
  return false;
}

function hasChaliceEligibleOpponent(state) {
  // Chalice needs an opponent with more cards than (my hand - 1 for Chalice itself)
  // At render time the card is still in hand, so subtract 1
  const myEffectiveSize = (state.you.hand || []).length - 1;
  if (myEffectiveSize < 0) return false;
  if ((state.you.discardPile || []).length === 0) return false;
  for (const opp of (state.others || [])) {
    if ((opp.cardCount || 0) > myEffectiveSize) return true;
  }
  return false;
}

function hasPortalEligibleStudent(state) {
  const myStudentName = state.you.chosenStudent?.name || null;
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    for (const c of (p.discardPile || [])) {
      if (c.type === 'Student' && c.name !== myStudentName) return true;
    }
  }
  return false;
}

function hasAnyTappedTarget(state) {
  const allPlayers = [state.you, ...(state.others || [])];
  for (const p of allPlayers) {
    if (p.tappedStudent) return true;
    if ((p.tappedFamiliars || []).length > 0) return true;
  }
  return false;
}

function hasOpponentDiscardCard(state) {
  for (const opp of (state.others || [])) {
    if (!opp.left && (opp.discardPile || []).length > 0) return true;
  }
  return false;
}

function hasAnyDiscardFamiliar(state) {
  // Check own discard
  for (const c of (state.you?.discardPile || [])) {
    if (c.type === 'Familiar') return true;
  }
  // Check opponents' discards
  for (const opp of (state.others || [])) {
    if (opp.left) continue;
    for (const c of (opp.discardPile || [])) {
      if (c.type === 'Familiar') return true;
    }
  }
  return false;
}

function hasAnyDamagedTarget(state) {
  const checkEntity = (e) => e && e.currentHp > 0 && e.currentHp < e.hp;
  if (checkEntity(state.you?.chosenStudent)) return true;
  for (const f of (state.you?.familiars || [])) { if (checkEntity(f)) return true; }
  for (const opp of (state.others || [])) {
    if (opp.left) continue;
    if (checkEntity(opp.chosenStudent)) return true;
    for (const f of (opp.familiars || [])) { if (checkEntity(f)) return true; }
  }
  return false;
}

function hasHistoricRecordsTarget(state) {
  // Server computes this — it requires access to the snapshot which only the server has
  return state.historicRecordsEligible === true;
}

function hasAnyUntappedFamiliar(state) {
  // For targeting effects (Magic Amber): excludes mechImmune, classPetImmunity, goldenHindImmune
  const checkBoard = (owner, tapped) => {
    if (owner.classPetImmunity) return false;
    for (let i = 0; i < (owner.familiars || []).length; i++) {
      const f = owner.familiars[i];
      if (!f || f.currentHp <= 0 || f.summoned || f.mechImmune || f.goldenHindImmune) continue;
      if ((tapped || []).includes(i)) continue;
      return true;
    }
    return false;
  };
  if (checkBoard(state.you, state.you?.tappedFamiliars)) return true;
  for (const opp of (state.others || [])) {
    if (opp.left) continue;
    if (checkBoard(opp, opp.tappedFamiliars)) return true;
  }
  return false;
}

function hasAnyUntappedFamiliarAoE(state) {
  // For AoE effects (Magic Ruby): excludes mechImmune + classPetImmunity, but NOT goldenHindImmune
  const checkBoard = (owner, tapped) => {
    if (owner.classPetImmunity) return false;
    for (let i = 0; i < (owner.familiars || []).length; i++) {
      const f = owner.familiars[i];
      if (!f || f.currentHp <= 0 || f.summoned || f.mechImmune) continue;
      if ((tapped || []).includes(i)) continue;
      return true;
    }
    return false;
  };
  if (checkBoard(state.you, state.you?.tappedFamiliars)) return true;
  for (const opp of (state.others || [])) {
    if (opp.left) continue;
    if (checkBoard(opp, opp.tappedFamiliars)) return true;
  }
  return false;
}

function hasStealableFamiliar(state) {
  for (const opp of (state.others || [])) {
    if (opp.classPetImmunity) continue;
    for (const f of (opp.familiars || [])) {
      if (f && f.currentHp > 0 && !f.summoned && !f.mechImmune && !f.goldenHindImmune) return true;
    }
  }
  return false;
}

function hasGigaSteroidTarget(state) {
  return (state.you.gigaSteroidEligibleCount || 0) > 0;
}

function exitDiscardMode() {
  if (discardMode && discardMode.elixirMode) {
    discardMode = null;
    emit('game:consideringCard', { cardIndex: -1 });
    rerenderHand();
    updateButtons();
    if (lastState) renderMyBoard(lastState);
    emit('elixir:cancelPay');
    return;
  }
  if (discardMode && discardMode.priceTagPayMode) {
    // Price Tag overpay is mandatory — cannot be cancelled. Do nothing.
    return;
  }
  discardMode = null;
  emit('game:consideringCard', { cardIndex: -1 });
  rerenderHand();
  updateButtons();
  if (lastState) renderMyBoard(lastState);
}

// Returns effective payment count considering Treasure Chest bonus.
// Each TC in selectedPayment counts as up to 3 total (1 card + up to 2 bonus slots).
function getTCEffectiveCount(dm) {
  const hand = lastState?.you?.hand || [];
  let tcCount = 0;
  for (const i of dm.selectedPayment) {
    if ((hand[i] || {}).name === 'Treasure Chest') tcCount++;
  }
  const nonTc = dm.selectedPayment.size - tcCount;
  if (tcCount === 0) return dm.selectedPayment.size;
  if (dm.cost === -1) {
    const cap = dm.maxCost != null ? dm.maxCost : Infinity;
    const bonus = Math.min(tcCount * 2, Math.max(0, (cap === Infinity ? tcCount * 2 : cap) - nonTc - tcCount));
    return nonTc + tcCount + bonus;
  } else {
    const bonus = Math.min(tcCount * 2, Math.max(0, dm.cost - nonTc - tcCount));
    return nonTc + tcCount + bonus;
  }
}

function togglePaymentCard(idx) {
  if (!discardMode) return;
  const hand = lastState?.you?.hand || [];
  const isTC = (hand[idx] || {}).name === 'Treasure Chest';
  if (discardMode.selectedPayment.has(idx)) {
    discardMode.selectedPayment.delete(idx);
  } else if (discardMode.cost === -1) {
    const cap = discardMode.maxCost != null ? discardMode.maxCost : Infinity;
    // TC may be added even if effective count is at cap, as long as raw size is under cap
    const effectiveAfter = getTCEffectiveCount({ ...discardMode, selectedPayment: new Set([...discardMode.selectedPayment, idx]) });
    if (effectiveAfter <= (cap === Infinity ? Infinity : cap)) discardMode.selectedPayment.add(idx);
  } else {
    // Fixed cost: TC counts as up to 3 — allow selection if adding it still reaches cost
    const effectiveAfter = getTCEffectiveCount({ ...discardMode, selectedPayment: new Set([...discardMode.selectedPayment, idx]) });
    if (isTC ? effectiveAfter <= discardMode.cost : discardMode.selectedPayment.size < discardMode.cost) {
      discardMode.selectedPayment.add(idx);
    }
  }
  rerenderHand();
  updateButtons();
  // Update server with current selection for timeout auto-play
  emit('game:consideringCard', { cardIndex: discardMode.cardIndex, selectedPayment: [...discardMode.selectedPayment] });
}

function confirmDiscard() {
  if (!discardMode) return;
  const minNeeded = discardMode.cost === -1 ? (discardMode.minCost ?? 1) : discardMode.cost;
  const exactNeeded = discardMode.cost === -1 ? false : true;
  const effectiveCount = getTCEffectiveCount(discardMode);
  if (exactNeeded && effectiveCount !== minNeeded) return;
  if (!exactNeeded && effectiveCount < minNeeded) return;

  // Elixir of Immortality reactive payment
  if (discardMode.elixirMode) {
    emit('elixir:pay', { paymentIndices: [...discardMode.selectedPayment] });
    discardMode = null;
    return;
  }

  // Price Tag overpay payment
  if (discardMode.priceTagPayMode) {
    emit('priceTag:payConfirm', { paymentIndices: [...discardMode.selectedPayment] });
    discardMode = null;
    return;
  }

  // Grave Crawler from discard pile
  if (discardMode.graveCrawlerDiscardIndex != null) {
    emit('game:playGraveCrawler', {
      discardIndex: discardMode.graveCrawlerDiscardIndex,
      paymentIndices: [...discardMode.selectedPayment],
      ...(discardMode.prodigyFree ? { prodigyIgnoreCost: true } : {}),
      ...(discardMode.summoningCircle ? { summoningCircle: true } : {}),
    });
    discardMode = null;
    return;
  }

  emit('game:playCard', {
    cardIndex: discardMode.cardIndex,
    paymentIndices: [...discardMode.selectedPayment],
    ...(discardMode.prodigyFree ? { prodigyIgnoreCost: true } : {}),
  });
  discardMode = null;
}

function enterGraveCrawlerPayment(discardIndex, cost, extraFlags = {}) {
  const isVar = extraFlags.isVariableCost || cost === -1;
  discardMode = {
    cardIndex: -1,
    cost: isVar ? -1 : cost,
    minCost: isVar ? (extraFlags.minCost ?? 1) : cost,
    maxCost: isVar ? (extraFlags.maxCost ?? null) : cost,
    selectedPayment: new Set(),
    graveCrawlerDiscardIndex: discardIndex,
    ...extraFlags,
  };
  rerenderHand();
  updateButtons();
  if (lastState) renderMyBoard(lastState);
}

// ═══════════════════════════════════════════════════════════════════════════
//  DISCARD VIEWER
// ═══════════════════════════════════════════════════════════════════════════
let discardViewerOpen = false;

function openDiscardViewer(playerName, discardPile) {
  if (!discardPile || discardPile.length === 0) return;
  discardViewerOpen = true;
  $discardViewerTitle.textContent = `${playerName}'s Discard Pile (${discardPile.length})`;
  $discardViewerCards.innerHTML = '';
  discardPile.forEach(card => {
    const $c = document.createElement('div');
    $c.className = 'discard-viewer-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    $c.setAttribute('data-no-zoom-lock', '');
    setZoomable($c, cardImg(card));
    $discardViewerCards.appendChild($c);
  });
  $discardViewer.classList.remove('hidden');
}

function closeDiscardViewer() {
  if (!discardViewerOpen) return;
  discardViewerOpen = false;
  $discardViewer.classList.add('hidden');
  $discardViewerCards.innerHTML = '';
}

// ═══════════════════════════════════════════════════════════════════════════
//  REVIVE PICKER (Phoenix — select a familiar from discard pile)
// ═══════════════════════════════════════════════════════════════════════════

function showRevivePicker(discardFamiliars) {
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent = 'Choose a Familiar to revive!';
  for (const { discardIndex, card } of discardFamiliars) {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      emit('familiar:revive', { discardIndex });
      hideRevivePicker();
      targetingMode = null;
    });
    // Name label below
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $revivePickerCards.appendChild($c);
  }
  $revivePicker.classList.remove('hidden');
}

function showResuscitationPicker(allDiscardFamiliars) {
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent = '💊 Choose a Familiar to revive from any discard!';
  for (const { playerId, playerName, discardIndex, card } of allDiscardFamiliars) {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      emit('item:resuscitationPotion', { playerId, discardIndex });
      hideRevivePicker();
      targetingMode = null;
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = playerName !== lastState?.you?.name ? `${card.name} (${playerName})` : card.name;
    $c.appendChild($label);
    $revivePickerCards.appendChild($c);
  }
  $revivePicker.classList.remove('hidden');
}

function showSmugglersCratePicker(allDiscardCards, selectedPicks) {
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent = "📦 Smugglers Crate: Select 1–2 cards to give to an opponent";

  // Confirm button
  const $confirmRow = document.createElement('div');
  $confirmRow.className = 'smugglers-confirm-row';
  const $confirm = document.createElement('button');
  $confirm.className = 'smugglers-confirm-btn';
  $confirm.textContent = `Confirm (${selectedPicks.length}/2) →`;
  $confirm.disabled = selectedPicks.length === 0;
  $confirmRow.appendChild($confirm);

  for (const { playerId, playerName, discardIndex, card } of allDiscardCards) {
    const key = `${playerId}:${discardIndex}`;
    const isSelected = selectedPicks.some(p => `${p.playerId}:${p.discardIndex}` === key);
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card smugglers-card' + (isSelected ? ' smugglers-selected' : '');
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');

    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!targetingMode || targetingMode.effectType !== 'smugglers-crate-pick') return;
      const idx = targetingMode.selectedPicks.findIndex(p => `${p.playerId}:${p.discardIndex}` === key);
      if (idx !== -1) {
        // Deselect
        targetingMode.selectedPicks.splice(idx, 1);
      } else {
        if (targetingMode.selectedPicks.length >= 2) return; // max 2
        targetingMode.selectedPicks.push({ playerId, discardIndex });
      }
      showSmugglersCratePicker(targetingMode.allDiscardCards, targetingMode.selectedPicks);
    });

    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    const myName = lastState?.you?.name;
    $label.textContent = playerName !== myName ? `${card.name} (${playerName})` : card.name;
    if (isSelected) {
      const $badge = document.createElement('span');
      $badge.className = 'smugglers-selected-badge';
      $badge.textContent = '✓';
      $c.appendChild($badge);
    }
    $c.appendChild($label);
    $revivePickerCards.appendChild($c);
  }

  $revivePickerCards.appendChild($confirmRow);

  $confirm.onclick = (e) => {
    e.stopPropagation();
    if (!targetingMode || targetingMode.selectedPicks.length === 0) return;
    const picks = targetingMode.selectedPicks;
    const savedAllDiscardCards = targetingMode.allDiscardCards;
    emit('item:smugglersCratePick', { picks });
    // Server will respond with smugglers-crate-opponent → state handler opens select-opponent mode
    // Keep allDiscardCards in case cancel needs to return here
    targetingMode = { effectType: 'smugglers-crate-opponent-pending', allDiscardCards: savedAllDiscardCards, selectedPicks: picks, canCancel: true };
    hideRevivePicker();
  };

  $revivePicker.classList.remove('hidden');
}


function showSmugglersCrateAnimation(state) {
  const evt = state.smugglersCrateEvent;
  if (!evt) return;
  const target = evt.targetPlayerId === state.you.id;
  let $hand = target
    ? document.getElementById('hand-cards')
    : (() => { const $el = opponentElements.get(evt.targetPlayerId); return $el ? $el.querySelector('.opponent-cards') : null; })();

  const cx = window.innerWidth / 2, cy = window.innerHeight / 2;
  evt.cards.forEach((card, i) => {
    setTimeout(() => {
      const $p = document.createElement('div');
      $p.className = 'shard-draw-preview'; // reuse shard preview style
      $p.style.left = cx + 'px';
      $p.style.top = (cy - 40 + i * 30) + 'px';
      $p.style.filter = 'drop-shadow(0 0 12px #f9c74f) drop-shadow(0 0 24px #e76f51)';
      const $img = document.createElement('img');
      $img.src = card.path;
      $p.appendChild($img);
      const $lbl = document.createElement('div');
      $lbl.className = 'shard-draw-label';
      $lbl.textContent = `→ ${evt.targetName}: ${card.name}`;
      $p.appendChild($lbl);
      document.body.appendChild($p);
      requestAnimationFrame(() => {
        if ($hand) {
          const r = $hand.getBoundingClientRect();
          $p.style.setProperty('--tx', (r.left + r.width / 2 - cx) + 'px');
          $p.style.setProperty('--ty', (r.top + r.height / 2 - (cy - 40 + i * 30)) + 'px');
        } else {
          $p.style.setProperty('--tx', '0px');
          $p.style.setProperty('--ty', target ? '200px' : '-200px');
        }
        $p.classList.add('shard-draw-fly');
      });
      setTimeout(() => $p.remove(), 600);
    }, i * 140);
  });
}

