function showTinyPhoenixSummonPicker(eligibleFamiliars) {
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent = '🔥🐦 Choose a Familiar to summon!';
  for (const entry of eligibleFamiliars) {
    const { ownerPlayerId, ownerName, discardIndex, card, cost, isVariableCost, minCost, maxCost } = entry;
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!isVariableCost && cost === 0) {
        // Free summon — emit immediately
        emit('familiar:tinyPhoenixSummon', { ownerPlayerId, discardIndex, paymentIndices: [] });
        hideRevivePicker();
        targetingMode = null;
      } else if (isVariableCost) {
        // Variable cost — Prodigy can skip but still pick count
        hideRevivePicker();
        const handSize = lastState ? (lastState.you.hand || []).length : 0;
        const enterVarPay = (prodigyFree) => {
          targetingMode = {
            effectType: 'tiny-phoenix-pay',
            ownerPlayerId, discardIndex,
            cost: -1, isVariableCost: true,
            minCost: minCost ?? 1,
            maxCost: Math.min(maxCost || handSize, handSize),
            cardName: card.name,
            selectedPayment: new Set(), canCancel: true,
            prodigyFree: !!prodigyFree,
          };
          if (lastState) renderHand(lastState);
          updateTargetingUI();
        };
        attemptProdigyCostIgnore(-1, () => enterVarPay(true), () => enterVarPay(false));
      } else {
        // Fixed cost — Prodigy intercept
        hideRevivePicker();
        attemptProdigyCostIgnore(cost,
          () => {
            emit('familiar:tinyPhoenixSummon', { ownerPlayerId, discardIndex, paymentIndices: [], prodigyIgnoreCost: true });
            targetingMode = null;
          },
          () => {
            targetingMode = {
              effectType: 'tiny-phoenix-pay',
              ownerPlayerId, discardIndex,
              cost, isVariableCost: false,
              minCost: cost, maxCost: cost,
              cardName: card.name,
              selectedPayment: new Set(), canCancel: true,
            };
            if (lastState) renderHand(lastState);
            updateTargetingUI();
          }
        );
      }
    });
    const costLabel = isVariableCost ? 'X' : `${cost}`;
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = `${card.name} (${ownerName}) [${costLabel}]`;
    $c.appendChild($label);
    $revivePickerCards.appendChild($c);
  }
  $revivePicker.classList.remove('hidden');
}

