function showWantedPosterPicker(discardPile, needed) {
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent =
    `🪧 Wanted Poster — Choose ${needed} card${needed > 1 ? 's' : ''} to retrieve from your discard!`;
  discardPile.forEach((card, i) => {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    const isSelected = targetingMode && targetingMode.effectType === 'wanted-poster-retrieve'
      && targetingMode.selectedIndices.has(i);
    $c.classList.toggle('target-selected', !!isSelected);
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!targetingMode || targetingMode.effectType !== 'wanted-poster-retrieve') return;
      if (targetingMode.selectedIndices.has(i)) {
        targetingMode.selectedIndices.delete(i);
      } else if (targetingMode.selectedIndices.size < targetingMode.needed) {
        targetingMode.selectedIndices.add(i);
      }
      showWantedPosterPicker(lastState.you.discardPile, targetingMode.needed);
      updateTargetingUI();
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $revivePickerCards.appendChild($c);
  });

  // Confirm button wrapped in a full-width row to match standard picker styling
  const $btnRow = document.createElement('div');
  $btnRow.className = 'caretaker-btn-row';
  const $confirm = document.createElement('button');
  const n = targetingMode && targetingMode.effectType === 'wanted-poster-retrieve'
    ? targetingMode.selectedIndices.size : 0;
  const canConfirm = n >= needed;
  $confirm.className = 'caretaker-summon-btn' + (canConfirm ? '' : ' disabled');
  $confirm.textContent = `Retrieve! (${n}/${needed})`;
  $confirm.addEventListener('click', (e) => {
    e.stopPropagation();
    if (!targetingMode || targetingMode.effectType !== 'wanted-poster-retrieve') return;
    if (targetingMode.selectedIndices.size !== targetingMode.needed) return;
    emit('familiar:wantedPosterRetrieve', { discardIndices: [...targetingMode.selectedIndices] });
    hideRevivePicker();
    targetingMode = null;
  });
  $btnRow.appendChild($confirm);
  $revivePickerCards.appendChild($btnRow);

  $revivePicker.classList.remove('hidden');
}

