function showCaretakerSummonPicker(restoredSelection) {
  const you = lastState?.you;
  if (!you) return;

  // Gather available familiars
  const handFams = [];
  const gerryBlocked = lastState?.gerrymanderOnBoard;
  for (let i = 0; i < you.hand.length; i++) {
    if (you.hand[i].type === 'Familiar') {
      if (gerryBlocked && you.hand[i].name === 'Gerrymander') continue;
      handFams.push({ source: 'hand', index: i, card: you.hand[i] });
    }
  }
  const discardFams = [];
  const mummyLock = !!lastState?.mummyGuardsLock;
  for (let i = 0; i < (you.discardPile || []).length; i++) {
    if (you.discardPile[i].type === 'Familiar') {
      if (gerryBlocked && you.discardPile[i].name === 'Gerrymander') continue;
      if (mummyLock) continue; // 🩻 Mummy Guards: Familiars locked in discard
      discardFams.push({ source: 'discard', index: i, card: you.discardPile[i] });
    }
  }
  const allFams = [...handFams, ...discardFams];
  const handSize = you.hand.length;
  const famDiscount = you.familiarCostReduction || 0;
  const prepDiscount = you.prepCostReduction || 0;

  function getFamCost(card) {
    let c = card.cost || 0;
    if (famDiscount) {
      let fcr = famDiscount;
      // Great King Trex doesn't benefit from its own cost reduction
      if (card.name === 'Great King Trex') {
        const trex = (lastState && lastState.you.trexReduction) || 0;
        fcr = Math.max(0, fcr - trex);
      }
      c = Math.max(0, c - fcr);
    }
    if (prepDiscount) c = Math.max(0, c - prepDiscount);
    return c;
  }

  // Selection state
  const selected = restoredSelection || []; // array of { source, index }

  function getSelectedCost() {
    let cost = 0;
    for (const s of selected) {
      const fam = allFams.find(f => f.source === s.source && f.index === s.index);
      if (fam) cost += getFamCost(fam.card);
    }
    return cost;
  }

  function getBudget() {
    // Budget = hand size minus hand familiars that are selected (those leave the hand)
    const handPicks = selected.filter(s => s.source === 'hand').length;
    return handSize - handPicks;
  }

  function canAfford(fam, isSelected) {
    const currentCost = getSelectedCost();
    const currentBudget = getBudget();
    if (isSelected) return true; // can always deselect
    if (selected.length >= 2) return false;
    const addedCost = getFamCost(fam.card);
    const newBudget = fam.source === 'hand' ? currentBudget - 1 : currentBudget;
    return addedCost <= newBudget - (currentCost);
  }

  function renderPhase1() {
    $revivePickerCards.innerHTML = '';
    $revivePicker.querySelector('.revive-picker-title').textContent = '🐾 Summon up to 2 Familiars!';

    // Info bar
    const $info = document.createElement('div');
    $info.className = 'caretaker-info';
    $info.textContent = `Cost: ${getSelectedCost()} / Budget: ${getBudget()}`;
    $revivePickerCards.appendChild($info);

    // Section labels + cards
    if (handFams.length > 0) {
      const $label = document.createElement('div');
      $label.className = 'caretaker-section-label';
      $label.textContent = '— Hand —';
      $revivePickerCards.appendChild($label);
    }
    for (const fam of handFams) {
      const isSelected = selected.some(s => s.source === 'hand' && s.index === fam.index);
      const affordable = canAfford(fam, isSelected);
      const $c = document.createElement('div');
      $c.className = 'revive-picker-card' + (isSelected ? ' caretaker-selected' : '') + (!affordable && !isSelected ? ' caretaker-unaffordable' : '');
      $c.style.backgroundImage = `url("${cardImg(fam.card)}")`;
      setZoomable($c, cardImg(fam.card));
      // Cost badge
      const $cost = document.createElement('span');
      $cost.className = 'caretaker-cost-badge';
      $cost.textContent = `💰${getFamCost(fam.card)}`;
      $c.appendChild($cost);
      if (affordable || isSelected) {
        $c.setAttribute('data-interactive', '');
        $c.addEventListener('click', (e) => {
          e.stopPropagation();
          if (isSelected) {
            const idx = selected.findIndex(s => s.source === 'hand' && s.index === fam.index);
            if (idx >= 0) selected.splice(idx, 1);
          } else {
            selected.push({ source: 'hand', index: fam.index });
          }
          renderPhase1();
        });
      }
      $revivePickerCards.appendChild($c);
    }

    if (discardFams.length > 0) {
      const $label = document.createElement('div');
      $label.className = 'caretaker-section-label';
      $label.textContent = '— Discard —';
      $revivePickerCards.appendChild($label);
    }
    for (const fam of discardFams) {
      const isSelected = selected.some(s => s.source === 'discard' && s.index === fam.index);
      const affordable = canAfford(fam, isSelected);
      const $c = document.createElement('div');
      $c.className = 'revive-picker-card' + (isSelected ? ' caretaker-selected' : '') + (!affordable && !isSelected ? ' caretaker-unaffordable' : '');
      $c.style.backgroundImage = `url("${cardImg(fam.card)}")`;
      setZoomable($c, cardImg(fam.card));
      const $cost = document.createElement('span');
      $cost.className = 'caretaker-cost-badge';
      $cost.textContent = `💰${getFamCost(fam.card)}`;
      $c.appendChild($cost);
      if (affordable || isSelected) {
        $c.setAttribute('data-interactive', '');
        $c.addEventListener('click', (e) => {
          e.stopPropagation();
          if (isSelected) {
            const idx = selected.findIndex(s => s.source === 'discard' && s.index === fam.index);
            if (idx >= 0) selected.splice(idx, 1);
          } else {
            selected.push({ source: 'discard', index: fam.index });
          }
          renderPhase1();
        });
      }
      $revivePickerCards.appendChild($c);
    }

    // Summon button
    const totalCost = getSelectedCost();
    const canSummon = selected.length >= 1 && totalCost <= getBudget();
    const $btn = document.createElement('button');
    $btn.className = 'caretaker-summon-btn' + (canSummon ? '' : ' disabled');
    $btn.textContent = totalCost === 0 && selected.length > 0 ? 'Summon!' : `Summon! (discard ${totalCost})`;
    if (canSummon) {
      $btn.addEventListener('click', (e) => {
        e.stopPropagation();
        if (totalCost === 0) {
          // Free summon — no payment needed
          emit('student:caretakerSummon', {
            handFamiliarIndices: selected.filter(s => s.source === 'hand').map(s => s.index),
            discardFamiliarIndices: selected.filter(s => s.source === 'discard').map(s => s.index),
            paymentIndices: [],
          });
          hideRevivePicker();
          targetingMode = null;
        } else {
          // Prodigy intercept
          attemptProdigyCostIgnore(totalCost,
            () => {
              emit('student:caretakerSummon', {
                handFamiliarIndices: selected.filter(s => s.source === 'hand').map(s => s.index),
                discardFamiliarIndices: selected.filter(s => s.source === 'discard').map(s => s.index),
                paymentIndices: [],
                prodigyIgnoreCost: true,
              });
              hideRevivePicker();
              targetingMode = null;
            },
            () => renderPhase2()
          );
        }
      });
    }
    $revivePickerCards.appendChild($btn);

    $revivePicker.classList.remove('hidden');
  }

  function renderPhase2() {
    $revivePickerCards.innerHTML = '';
    const totalCost = getSelectedCost();
    $revivePicker.querySelector('.revive-picker-title').textContent = `📤 Discard ${totalCost} card${totalCost !== 1 ? 's' : ''} to pay!`;

    // Store phase on targetingMode for back/cancel handling
    if (targetingMode) targetingMode.caretakerPhase = 'payment';

    const handFamIndices = new Set(selected.filter(s => s.source === 'hand').map(s => s.index));
    const payable = [];
    for (let i = 0; i < you.hand.length; i++) {
      if (handFamIndices.has(i)) continue; // can't discard selected familiars
      payable.push({ handIndex: i, card: you.hand[i] });
    }

    const payment = []; // selected hand indices for payment

    function renderPaymentCards() {
      $revivePickerCards.innerHTML = '';

      // Info
      const $info = document.createElement('div');
      $info.className = 'caretaker-info';
      $info.textContent = `Selected: ${payment.length} / ${totalCost}`;
      $revivePickerCards.appendChild($info);

      for (const p of payable) {
        const isPicked = payment.includes(p.handIndex);
        const $c = document.createElement('div');
        $c.className = 'revive-picker-card' + (isPicked ? ' caretaker-selected' : '');
        $c.style.backgroundImage = `url("${cardImg(p.card)}")`;
        setZoomable($c, cardImg(p.card));
        $c.setAttribute('data-interactive', '');
        $c.addEventListener('click', (e) => {
          e.stopPropagation();
          if (isPicked) {
            const idx = payment.indexOf(p.handIndex);
            if (idx >= 0) payment.splice(idx, 1);
          } else if (payment.length < totalCost) {
            payment.push(p.handIndex);
          }
          renderPaymentCards();
        });
        $revivePickerCards.appendChild($c);
      }

      // Buttons row
      const $btnRow = document.createElement('div');
      $btnRow.className = 'caretaker-btn-row';

      const $back = document.createElement('button');
      $back.className = 'caretaker-back-btn';
      $back.textContent = '← Back';
      $back.addEventListener('click', (e) => {
        e.stopPropagation();
        if (targetingMode) targetingMode.caretakerPhase = 'select';
        renderPhase1();
      });
      $btnRow.appendChild($back);

      const canConfirm = payment.length === totalCost;
      const $confirm = document.createElement('button');
      $confirm.className = 'caretaker-summon-btn' + (canConfirm ? '' : ' disabled');
      $confirm.textContent = 'Confirm!';
      if (canConfirm) {
        $confirm.addEventListener('click', (e) => {
          e.stopPropagation();
          emit('student:caretakerSummon', {
            handFamiliarIndices: selected.filter(s => s.source === 'hand').map(s => s.index),
            discardFamiliarIndices: selected.filter(s => s.source === 'discard').map(s => s.index),
            paymentIndices: payment,
          });
          hideRevivePicker();
          targetingMode = null;
        });
      }
      $btnRow.appendChild($confirm);

      $revivePickerCards.appendChild($btnRow);
    }

    renderPaymentCards();
  }

  // Start at phase 1
  if (targetingMode) targetingMode.caretakerPhase = 'select';
  renderPhase1();
}

function showNerdRetrievePicker() {
  const you = lastState?.you;
  if (!you) return;

  const discard = you.discardPile || [];
  const selected = []; // array of discard indices
  const mummyLockNerd = !!lastState?.mummyGuardsLock;

  function render() {
    $revivePickerCards.innerHTML = '';
    $revivePicker.querySelector('.revive-picker-title').textContent = `📚 Retrieve up to 3 cards! (${selected.length}/3)`;

    for (let i = 0; i < discard.length; i++) {
      const card = discard[i];
      const isSelected = selected.includes(i);
      const locked = mummyLockNerd && card.type === 'Familiar';
      const $c = document.createElement('div');
      $c.className = 'revive-picker-card' + (isSelected ? ' caretaker-selected' : '');
      $c.style.backgroundImage = `url("${cardImg(card)}")`;
      setZoomable($c, cardImg(card));
      $c.setAttribute('data-interactive', '');
      if (locked) {
        $c.style.opacity = '0.4';
        $c.style.pointerEvents = 'none';
      }
      $c.addEventListener('click', (e) => {
        e.stopPropagation();
        if (isSelected) {
          const idx = selected.indexOf(i);
          if (idx >= 0) selected.splice(idx, 1);
        } else if (selected.length < 3) {
          selected.push(i);
        }
        render();
      });
      $revivePickerCards.appendChild($c);
    }

    // Confirm button
    const canConfirm = selected.length >= 1;
    const $btn = document.createElement('button');
    $btn.className = 'caretaker-summon-btn' + (canConfirm ? '' : ' disabled');
    $btn.textContent = selected.length > 0 ? `Retrieve ${selected.length} card${selected.length > 1 ? 's' : ''}!` : 'Select cards…';
    if (canConfirm) {
      $btn.addEventListener('click', (e) => {
        e.stopPropagation();
        emit('student:nerdRetrieve', { discardIndices: [...selected] });
        hideRevivePicker();
        targetingMode = null;
      });
    }
    $revivePickerCards.appendChild($btn);

    $revivePicker.classList.remove('hidden');
  }

  render();
}

