// ═══════════════════════════════════════════════════════════════════════════
//  EQUIP TRIGGER PICKER (Rain Viola etc. — pick a card from discard)
// ═══════════════════════════════════════════════════════════════════════════
let equipTriggerPickerShown = null; // track which trigger we're showing for

function updateSongOfRainUI(state) {
  let $modal = document.getElementById('song-of-rain-modal');
  const psor = state.pendingSongOfRain;
  if (!psor || !psor.isMyPrompt || psor.hasResponded) {
    if ($modal) $modal.remove();
    return;
  }
  if ($modal) return; // already shown
  $modal = document.createElement('div');
  $modal.id = 'song-of-rain-modal';
  $modal.className = 'song-of-rain-modal';
  const elapsed = Date.now() - (psor.startedAt || Date.now());
  const remaining = Math.max(0, (psor.timeoutMs || 10000) - elapsed);

  const $title = document.createElement('div');
  $title.className = 'song-of-rain-title';
  $title.textContent = '🌧️ Stop singing?';
  $modal.appendChild($title);

  const $sub = document.createElement('div');
  $sub.className = 'song-of-rain-subtitle';
  $sub.textContent = 'Remove Song of Rain from your Student?';
  $modal.appendChild($sub);

  const $btns = document.createElement('div');
  $btns.className = 'song-of-rain-btns';

  const $yes = document.createElement('button');
  $yes.className = 'sor-btn sor-yes';
  $yes.textContent = '🎵 Stop Singing';
  $yes.onclick = () => { emit('songOfRain:stopSinging', { stop: true }); $modal.remove(); };

  const $no = document.createElement('button');
  $no.className = 'sor-btn sor-no';
  $no.textContent = '🌧️ Keep Singing';
  $no.onclick = () => { emit('songOfRain:stopSinging', { stop: false }); $modal.remove(); };

  // Countdown bar
  const $bar = document.createElement('div');
  $bar.className = 'sor-countdown-bar';
  const $fill = document.createElement('div');
  $fill.className = 'sor-countdown-fill';
  $fill.style.animationDuration = (remaining / 1000) + 's';
  $bar.appendChild($fill);

  $btns.appendChild($yes); $btns.appendChild($no);
  $modal.appendChild($btns);
  $modal.appendChild($bar);
  document.body.appendChild($modal);
}

function showEquipTriggerPicker(state) {
  const pet = state.pendingEquipTrigger;
  if (!pet || pet.playerId !== state.you.id || pet.effectType !== 'pick-from-discard') {
    hideEquipTriggerPicker();
    return;
  }

  // Don't re-render if already showing for same trigger
  const key = `${pet.playerId}-${pet.equipName}`;
  if (equipTriggerPickerShown === key) return;
  equipTriggerPickerShown = key;

  $equipTriggerPickerCards.innerHTML = '';
  $equipTriggerPicker.querySelector('.revive-picker-title').textContent =
    `🎻 ${pet.equipName} — Choose a card to add to your hand!`;

  const discard = state.you.discardPile || [];
  discard.forEach((card, idx) => {
    // Exclude the trigger card itself (same name, last occurrence in discard)
    if (card.name === pet.equipName) {
      // Find the last occurrence index of this equip name
      const lastIdx = discard.map((c, i) => c.name === pet.equipName ? i : -1).filter(i => i >= 0).pop();
      if (idx === lastIdx) return; // skip the trigger card
    }

    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      emit('equip:triggerPick', { discardIndex: idx });
      hideEquipTriggerPicker();
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $equipTriggerPickerCards.appendChild($c);
  });

  $equipTriggerPicker.classList.remove('hidden');
}

function hideEquipTriggerPicker() {
  $equipTriggerPicker.classList.add('hidden');
  $equipTriggerPickerCards.innerHTML = '';
  equipTriggerPickerShown = null;
}

function showReviveEquipPicker(discardEquips) {
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent = 'Choose an Equip to recover!';
  for (const { discardIndex, card } of discardEquips) {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      const cost = card.cost || 0;
      if (cost === 0) {
        emit('familiar:reviveEquip', { discardIndex, paymentIndices: [] });
        hideRevivePicker();
        targetingMode = null;
      } else {
        hideRevivePicker();
        attemptProdigyCostIgnore(cost,
          () => {
            emit('familiar:reviveEquip', { discardIndex, paymentIndices: [], prodigyIgnoreCost: true });
            targetingMode = null;
          },
          () => {
            // Enter payment mode
            targetingMode.payingFor = { discardIndex, cost, card };
            targetingMode.selectedPayment = new Set();
            if (lastState) renderHand(lastState);
            updateTargetingUI();
          }
        );
      }
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = `${card.name} (${card.cost || 0})`;
    $c.appendChild($label);
    $revivePickerCards.appendChild($c);
  }
  $revivePicker.classList.remove('hidden');
}

