function showShootingStarPicker(cards, currentSelection) {
  document.body.classList.add('shooting-star-active');
  $revivePickerCards.innerHTML = '';
  $revivePicker.querySelector('.revive-picker-title').textContent = '🌠 Wish for something…';

  for (const { name, count, path } of cards) {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    const img = cardImg({ name, path });
    $c.style.backgroundImage = `url("${img}")`;
    setZoomable($c, img);
    if (currentSelection === name) $c.classList.add('shooting-star-selected');

    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = name;
    $c.appendChild($label);

    if (count >= 1) {
      const $count = document.createElement('span');
      $count.className = 'shooting-star-count';
      $count.textContent = `×${count}`;
      $c.appendChild($count);
    }

    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!targetingMode || targetingMode.effectType !== 'shooting-star-pick') return;
      targetingMode.selected = targetingMode.selected === name ? null : name;
      // Update selection highlights in place
      $revivePickerCards.querySelectorAll('.revive-picker-card').forEach($x => $x.classList.remove('shooting-star-selected'));
      if (targetingMode.selected) $c.classList.add('shooting-star-selected');
      updateTargetingUI();
    });
    $revivePickerCards.appendChild($c);
  }
  $revivePicker.classList.remove('hidden');

  // Position targeting overlay just below the picker
  requestAnimationFrame(() => {
    const pickerRect = $revivePicker.getBoundingClientRect();
    const $overlay = document.getElementById('targeting-overlay');
    if ($overlay && pickerRect.height > 0) {
      $overlay.style.top    = (pickerRect.bottom + 20) + 'px';
      $overlay.style.bottom = 'auto';
    }
  });
}

