function showManaBeaconPicker(spells) {
  hideManaBeaconPicker();
  document.body.classList.add('mana-beacon-active');

  const $modal = document.createElement('div');
  $modal.id = 'mana-beacon-modal';
  $modal.className = 'mana-beacon-modal';

  const $title = document.createElement('div');
  $title.className = 'mana-beacon-title';
  $title.textContent = '🔵 Mana Beacon — Select up to 3 Spells to return to hand';
  $modal.appendChild($title);

  const $cards = document.createElement('div');
  $cards.className = 'mana-beacon-cards';

  for (const { discardIndex, name, path, cost } of spells) {
    const $c = document.createElement('div');
    $c.className = 'mana-beacon-card';
    $c.style.backgroundImage = `url("${path || CARDBACK}")`;
    setZoomable($c, path || CARDBACK);

    const $lbl = document.createElement('span');
    $lbl.className = 'revive-picker-label';
    $lbl.textContent = name;
    $c.appendChild($lbl);

    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!targetingMode || targetingMode.effectType !== 'mana-beacon-pick') return;
      const sels = targetingMode.selections;
      if (sels.has(discardIndex)) {
        sels.delete(discardIndex);
        $c.classList.remove('mana-beacon-selected');
      } else if (sels.size < 3) {
        sels.add(discardIndex);
        $c.classList.add('mana-beacon-selected');
      }
      updateTargetingUI();
    });
    $cards.appendChild($c);
  }

  $modal.appendChild($cards);
  document.body.appendChild($modal);
}

