function showUWEPicker(piles) {
  hideUWEPicker();
  document.body.classList.add('hole-in-sky-active');
  const $modal = document.createElement('div');
  $modal.id = 'uwe-modal';
  $modal.className = 'hole-in-sky-modal';

  const $title = document.createElement('div');
  $title.className = 'hole-in-sky-title';
  $title.textContent = '⚗️ Ultimate Weapon Experiment — Select up to 1 Equip per pile';
  $modal.appendChild($title);

  const $body = document.createElement('div');
  $body.className = 'hole-in-sky-body';

  for (const pile of piles) {
    const $row = document.createElement('div');
    $row.className = 'hole-in-sky-row';
    const $label = document.createElement('div');
    $label.className = 'hole-in-sky-row-label';
    $label.textContent = pile.playerName + "'s Discard";
    $row.appendChild($label);
    const $cards = document.createElement('div');
    $cards.className = 'hole-in-sky-cards';
    if (pile.cards.length === 0) {
      const $empty = document.createElement('span');
      $empty.className = 'hole-in-sky-empty';
      $empty.textContent = '(no Equips)';
      $cards.appendChild($empty);
    } else {
      for (const { discardIndex, name, path } of pile.cards) {
        const $c = document.createElement('div');
        $c.className = 'hole-in-sky-card';
        $c.style.backgroundImage = `url("${path || CARDBACK}")`;
        $c.dataset.playerId = pile.playerId;
        $c.dataset.discardIndex = discardIndex;
        setZoomable($c, path || CARDBACK);
        const $lbl = document.createElement('span');
        $lbl.className = 'revive-picker-label';
        $lbl.textContent = name;
        $c.appendChild($lbl);
        $c.addEventListener('click', (e) => {
          e.stopPropagation();
          if (!targetingMode || targetingMode.effectType !== 'uwe-pick') return;
          const sels = targetingMode.selections;
          if (sels[pile.playerId] === discardIndex) {
            delete sels[pile.playerId];
            $c.classList.remove('hole-in-sky-selected');
          } else {
            // Deselect previous from same pile
            if (sels[pile.playerId] != null) {
              $cards.querySelectorAll('.hole-in-sky-selected').forEach(el => el.classList.remove('hole-in-sky-selected'));
            }
            sels[pile.playerId] = discardIndex;
            $c.classList.add('hole-in-sky-selected');
          }
          updateTargetingUI();
        });
        $cards.appendChild($c);
      }
    }
    $row.appendChild($cards);
    $body.appendChild($row);
    const $sep = document.createElement('hr');
    $sep.className = 'hole-in-sky-sep';
    $body.appendChild($sep);
  }
  $modal.appendChild($body);
  document.body.appendChild($modal);
}

function showHoleInSkyPicker(piles) {
  hideHoleInSkyPicker();
  document.body.classList.add('hole-in-sky-active');
  const $modal = document.createElement('div');
  $modal.id = 'hole-in-sky-modal';
  $modal.className = 'hole-in-sky-modal';

  const $title = document.createElement('div');
  $title.className = 'hole-in-sky-title';
  $title.textContent = '🌑 Hole in the Sky — Select up to 3 cards per pile to delete';
  $modal.appendChild($title);

  const $body = document.createElement('div');
  $body.className = 'hole-in-sky-body';

  for (const pile of piles) {
    const $row = document.createElement('div');
    $row.className = 'hole-in-sky-row';

    const $label = document.createElement('div');
    $label.className = 'hole-in-sky-row-label';
    $label.textContent = pile.playerName + '\'s Discard';
    $row.appendChild($label);

    const $cards = document.createElement('div');
    $cards.className = 'hole-in-sky-cards';

    if (pile.cards.length === 0) {
      const $empty = document.createElement('span');
      $empty.className = 'hole-in-sky-empty';
      $empty.textContent = '(empty)';
      $cards.appendChild($empty);
    } else {
      for (const { discardIndex, name, path } of pile.cards) {
        const $c = document.createElement('div');
        $c.className = 'hole-in-sky-card';
        $c.style.backgroundImage = `url("${path || CARDBACK}")`;
        $c.dataset.playerId = pile.playerId;
        $c.dataset.discardIndex = discardIndex;
        setZoomable($c, path || CARDBACK);

        const $lbl = document.createElement('span');
        $lbl.className = 'revive-picker-label';
        $lbl.textContent = name;
        $c.appendChild($lbl);

        $c.addEventListener('click', (e) => {
          e.stopPropagation();
          if (!targetingMode || targetingMode.effectType !== 'hole-in-sky-pick') return;
          const sels = targetingMode.selections;
          if (!sels[pile.playerId]) sels[pile.playerId] = [];
          const arr = sels[pile.playerId];
          const pos = arr.indexOf(discardIndex);
          if (pos !== -1) {
            arr.splice(pos, 1);
            $c.classList.remove('hole-in-sky-selected');
          } else {
            if (arr.length >= 3) return; // max 3 per pile
            arr.push(discardIndex);
            $c.classList.add('hole-in-sky-selected');
          }
          updateTargetingUI();
        });
        $cards.appendChild($c);
      }
    }

    $row.appendChild($cards);
    $body.appendChild($row);

    // Separator line
    const $sep = document.createElement('hr');
    $sep.className = 'hole-in-sky-sep';
    $body.appendChild($sep);
  }

  $modal.appendChild($body);
  document.body.appendChild($modal);
}

export function hideLiveShowModal() {
  const $m = document.getElementById('live-show-modal');
  if ($m) $m.remove();
}

function showLiveShowModal(pls, state) {
  let $m = document.getElementById('live-show-modal');
  const alreadyVoted = pls.hasVoted;
  const isCaster = pls.casterId === state.you.id;

  if (!$m) {
    $m = document.createElement('div');
    $m.id = 'live-show-modal';
    $m.className = 'live-show-modal';
    document.body.appendChild($m);
  }

  const votedSoFar = pls.yesVotes + pls.noVotes;
  $m.innerHTML = `
    <div class="live-show-title">🎤 Live Show!</div>
    <div class="live-show-question">Should <strong>${pls.casterName}</strong> win the game?</div>
    <div class="live-show-tally">
      <span class="live-show-remaining">${pls.remainingVoters} player${pls.remainingVoters !== 1 ? 's' : ''} yet to vote</span>
    </div>
    ${!alreadyVoted ? `
      <div class="live-show-buttons">
        <button class="live-show-btn live-show-yes" id="btn-liveshow-yes">✅ Yes!</button>
        <button class="live-show-btn live-show-no"  id="btn-liveshow-no">❌ No!</button>
      </div>
    ` : `<div class="live-show-voted">Your vote has been counted!</div>`}
  `;

  if (!alreadyVoted) {
    $m.querySelector('#btn-liveshow-yes').addEventListener('click', () => {
      emit('liveShow:vote', { vote: 'yes' });
    });
    $m.querySelector('#btn-liveshow-no').addEventListener('click', () => {
      emit('liveShow:vote', { vote: 'no' });
    });
  }
}

