// ═══════════════════════════════════════════════════════════════════════════
//  SMUG COIN PICKER (multi-select from own discard pile)
// ═══════════════════════════════════════════════════════════════════════════

let smugCoinSelected = new Set();
let smugCoinPickCount = 0;

function showSmugCoinPicker(discardPile, pickCount) {
  smugCoinSelected = new Set();
  smugCoinPickCount = pickCount;
  $smugCoinPickerCards.innerHTML = '';
  $smugCoinPicker.querySelector('.revive-picker-title').textContent = `🪙 Choose ${pickCount} card${pickCount > 1 ? 's' : ''} from your discard pile!`;
  const mummyLockSC = !!lastState?.mummyGuardsLock;

  discardPile.forEach((card, i) => {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card smug-coin-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.dataset.discardIndex = i;
    const locked = mummyLockSC && card.type === 'Familiar';
    if (locked) {
      $c.style.opacity = '0.4';
      $c.style.pointerEvents = 'none';
    }
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (smugCoinSelected.has(i)) {
        smugCoinSelected.delete(i);
        $c.classList.remove('smug-coin-selected');
      } else if (smugCoinSelected.size < smugCoinPickCount) {
        smugCoinSelected.add(i);
        $c.classList.add('smug-coin-selected');
      }
      updateSmugCoinConfirm();
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $smugCoinPickerCards.appendChild($c);
  });

  updateSmugCoinConfirm();
  $smugCoinPicker.classList.remove('hidden');
}

function updateSmugCoinConfirm() {
  const n = smugCoinSelected.size;
  $smugCoinConfirm.textContent = `Confirm (${n}/${smugCoinPickCount})`;
  $smugCoinConfirm.disabled = n !== smugCoinPickCount;
}

function hideSmugCoinPicker() {
  $smugCoinPicker.classList.add('hidden');
  $smugCoinPickerCards.innerHTML = '';
  smugCoinSelected = new Set();
}

$smugCoinConfirm.addEventListener('click', (e) => {
  e.stopPropagation();
  if (smugCoinSelected.size !== smugCoinPickCount) return;
  emit('item:smugCoinPick', { pickedIndices: [...smugCoinSelected] });
  hideSmugCoinPicker();
  targetingMode = null;
});

