// ═══════════════════════════════════════════════════════════════════════════
//  WINGED CAMERA PICKER
// ═══════════════════════════════════════════════════════════════════════════

let wcSelected = new Set();   // Set of snapshotIndex numbers
let wcOwnerLock = null;       // ownerId of the pile currently being picked from

function showWingedCameraPicker(discardFamiliars) {
  wcSelected = new Set();
  wcOwnerLock = null;
  $wcPickerCards.innerHTML = '';

  // Group by ownerId, preserving the order from the server (own first)
  const groups = [];
  const seen = new Map();
  for (const entry of discardFamiliars) {
    if (!seen.has(entry.ownerId)) {
      seen.set(entry.ownerId, []);
      groups.push({ ownerId: entry.ownerId, playerName: entry.playerName, entries: seen.get(entry.ownerId) });
    }
    seen.get(entry.ownerId).push(entry);
  }

  groups.forEach((group, gi) => {
    // Owner label / separator
    const $sep = document.createElement('div');
    $sep.className = 'wc-owner-label';
    $sep.textContent = group.playerName + "'s Discards";
    $wcPickerCards.appendChild($sep);

    // Cards for this owner
    const $row = document.createElement('div');
    $row.className = 'wc-card-row';
    for (const entry of group.entries) {
      const $c = document.createElement('div');
      $c.className = 'revive-picker-card chalice-card';
      $c.style.backgroundImage = `url("${cardImg(entry)}")`;
      setZoomable($c, cardImg(entry));
      $c.setAttribute('data-interactive', '');
      $c.dataset.snapshotIndex = entry.snapshotIndex;
      $c.dataset.ownerId = entry.ownerId;

      $c.addEventListener('click', (e) => {
        e.stopPropagation();
        const si = entry.snapshotIndex;
        const oid = entry.ownerId;

        if (wcSelected.has(si)) {
          // Deselect
          wcSelected.delete(si);
          $c.classList.remove('chalice-selected');
          // If nothing selected, release the owner lock
          if (wcSelected.size === 0) wcOwnerLock = null;
        } else {
          // Can only pick from same pile
          if (wcOwnerLock !== null && wcOwnerLock !== oid) return;
          if (wcSelected.size >= 3) return;
          wcSelected.add(si);
          wcOwnerLock = oid;
          $c.classList.add('chalice-selected');
        }

        // Grey out cards from other owners while a pile is locked
        $wcPickerCards.querySelectorAll('.revive-picker-card').forEach($card => {
          const cardOid = $card.dataset.ownerId;
          if (wcOwnerLock !== null && cardOid !== wcOwnerLock) {
            $card.classList.add('wc-card-dimmed');
          } else {
            $card.classList.remove('wc-card-dimmed');
          }
        });

        updateWcConfirm();
      });

      $c.addEventListener('contextmenu', (e) => { e.preventDefault(); e.stopPropagation(); cancelWcPicker(); });

      const $label = document.createElement('span');
      $label.className = 'revive-picker-label';
      $label.textContent = entry.name;
      $c.appendChild($label);
      $row.appendChild($c);
    }
    $wcPickerCards.appendChild($row);
  });

  updateWcConfirm();
  $wcPicker.classList.remove('hidden');
}

function updateWcConfirm() {
  const n = wcSelected.size;
  $wcConfirm.textContent = `Add to hand (${n}/3)`;
  $wcConfirm.disabled = (n < 1);
}

function hideWcPicker() {
  $wcPicker.classList.add('hidden');
  $wcPickerCards.innerHTML = '';
  wcSelected = new Set();
  wcOwnerLock = null;
}

function cancelWcPicker() {
  hideWcPicker();
  targetingMode = null;
  emit('wingedCamera:cancel');
}

$wcConfirm.addEventListener('click', (e) => {
  e.stopPropagation();
  if (wcSelected.size < 1 || !wcOwnerLock) return;
  emit('wingedCamera:confirm', { ownerId: wcOwnerLock, snapshotIndices: [...wcSelected] });
  hideWcPicker();
  targetingMode = null;
});

$wcCancelBtn.addEventListener('click', (e) => {
  e.stopPropagation();
  cancelWcPicker();
});

$wcPicker.addEventListener('contextmenu', (e) => {
  e.preventDefault();
  e.stopPropagation();
  cancelWcPicker();
});

