// ═══════════════════════════════════════════════════════════════════════════
//  PRICE TAG — reactive equip-cost doubler prompt
// ═══════════════════════════════════════════════════════════════════════════

let priceTagPromptShown     = false;
let priceTagOverpayShown    = false;

/**
 * Show the activation prompt to a Price Tag owner.
 * Uses the same snare-prompt overlay + timer pattern.
 */
function showPriceTagPrompt(pt) {
  if (priceTagPromptShown) return;
  priceTagPromptShown = true;

  $priceTagPromptTitle.textContent = '🏷️ Play Price Tag?';
  $priceTagPromptDesc.textContent  = `${pt.equipCardName} was just played — double its cost!`;
  $priceTagPromptButtons.innerHTML = '';

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = 'Yes — Play!';
  $yes.addEventListener('click', () => {
    emit('priceTag:activate');
    hidePriceTagPrompt();
  });
  $priceTagPromptButtons.appendChild($yes);

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No';
  $no.addEventListener('click', () => {
    emit('priceTag:decline');
    hidePriceTagPrompt();
  });
  $priceTagPromptButtons.appendChild($no);

  $priceTagPrompt.classList.remove('hidden');

  // Timer bar
  const elapsed    = Date.now() - pt.startedAt;
  const remaining  = Math.max(0, pt.timeoutMs - elapsed);
  const startFrac  = remaining / pt.timeoutMs;
  $priceTagTimerBar.style.transition = 'none';
  $priceTagTimerBar.style.width = (startFrac * 100) + '%';
  requestAnimationFrame(() => requestAnimationFrame(() => {
    $priceTagTimerBar.style.transition = `width ${remaining}ms linear`;
    $priceTagTimerBar.style.width = '0%';
  }));
}

function hidePriceTagPrompt() {
  priceTagPromptShown = false;
  $priceTagPrompt.classList.add('hidden');
  $priceTagPromptButtons.innerHTML = '';
}

/**
 * Show the overpay prompt to the equipping player.
 * They must choose Yes (enter payment) or No (equip discarded).
 */
function showPriceTagOverpayPrompt(pt) {
  if (priceTagOverpayShown) return;
  priceTagOverpayShown = true;

  $priceTagOverpayTitle.textContent = `💸 Overpay for ${pt.equipCardName}?`;
  $priceTagOverpayDesc.textContent  = `${pt.activatorName} played Price Tag — pay ${pt.equipCost} more card(s) to keep your equip, or discard it.`;
  $priceTagOverpayButtons.innerHTML = '';

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = `Yes — Pay ${pt.equipCost}`;
  $yes.addEventListener('click', () => {
    emit('priceTag:overpayYes');
    hidePriceTagOverpayPrompt();
  });
  $priceTagOverpayButtons.appendChild($yes);

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No — Discard it';
  $no.addEventListener('click', () => {
    emit('priceTag:overpayNo');
    hidePriceTagOverpayPrompt();
  });
  $priceTagOverpayButtons.appendChild($no);

  $priceTagOverpayPrompt.classList.remove('hidden');

  // Timer bar
  const elapsed    = Date.now() - pt.overpayStartedAt;
  const remaining  = Math.max(0, pt.overpayTimeoutMs - elapsed);
  const startFrac  = remaining / pt.overpayTimeoutMs;
  $priceTagOverpayTimerBar.style.transition = 'none';
  $priceTagOverpayTimerBar.style.width = (startFrac * 100) + '%';
  requestAnimationFrame(() => requestAnimationFrame(() => {
    $priceTagOverpayTimerBar.style.transition = `width ${remaining}ms linear`;
    $priceTagOverpayTimerBar.style.width = '0%';
  }));
}

function hidePriceTagOverpayPrompt() {
  priceTagOverpayShown = false;
  $priceTagOverpayPrompt.classList.add('hidden');
  $priceTagOverpayButtons.innerHTML = '';
}

