let warProfiteeringSelected = new Set();

function showWarProfiteeringPicker(options, count, actualTake) {
  if (warProfiteeringShown) { updateWarProfiteeringPicker(options, actualTake); return; }
  warProfiteeringShown = true;
  warProfiteeringSelected = new Set();
  $warProfiteeringTitle.textContent =
    actualTake === 0
      ? `💰 War Profiteering — No cards to recover! Taking ${count * 5} damage.`
      : actualTake === 1 ? '💰 War Profiteering — Select 1 Non-Item card to add to your hand!'
      : `💰 War Profiteering — Select ${actualTake} Non-Item card(s) to add to your hand!`;
  updateWarProfiteeringPicker(options, actualTake);
  $warProfiteeringPicker.classList.remove('hidden');
}

function updateWarProfiteeringPicker(options, actualTake) {
  $warProfiteeringCards.innerHTML = '';
  warProfiteeringSelected = new Set();
  for (const card of options) {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card war-profiteering-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")` ;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.dataset.idx = card.index;
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      const idx = card.index;
      if (warProfiteeringSelected.has(idx)) {
        warProfiteeringSelected.delete(idx);
        $c.classList.remove('war-profiteering-selected');
      } else {
        if (warProfiteeringSelected.size >= actualTake) return;
        warProfiteeringSelected.add(idx);
        $c.classList.add('war-profiteering-selected');
      }
      refreshWarProfiteeringConfirm(actualTake);
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $warProfiteeringCards.appendChild($c);
  }
  $warProfiteeringConfirm.classList.remove('hidden');
  $warProfiteeringConfirm.textContent = `Recover (0/${actualTake})`;
  $warProfiteeringConfirm.disabled = (actualTake > 0);
  $warProfiteeringConfirm.onclick = () => {
    if (warProfiteeringSelected.size !== actualTake) return;
    emit('warProfiteering:selectCards', { discardIndices: [...warProfiteeringSelected] });
    hideWarProfiteeringPicker();
  };
}

function refreshWarProfiteeringConfirm(actualTake) {
  const n = warProfiteeringSelected.size;
  $warProfiteeringConfirm.textContent = `Recover (${n}/${actualTake})`;
  $warProfiteeringConfirm.disabled = (n !== actualTake);
}

function hideWarProfiteeringPicker() {
  warProfiteeringShown = false;
  warProfiteeringSelected = new Set();
  $warProfiteeringPicker.classList.add('hidden');
  $warProfiteeringCards.innerHTML = '';
  $warProfiteeringConfirm.classList.add('hidden');
}

