// ═══════════════════════════════════════════════════════════════════════════

let goldenEggPromptShown = false;
let goldenEggPickerShown = false;

function showGoldenEggPrompt(hasEligible, hatchCounters, startedAt, timeoutMs) {
  if (goldenEggPromptShown) return;
  goldenEggPromptShown = true;
  $goldenEggPromptButtons.innerHTML = '';
  $goldenEggPromptTitle.textContent =
    `🥚 Hatch your Golden Egg? (${hatchCounters || 0} counter${(hatchCounters || 0) !== 1 ? 's' : ''})`;

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = 'Yes!';
  if (!hasEligible) {
    $yes.disabled = true;
    $yes.title = 'No eligible Familiars to hatch into';
  }
  $yes.addEventListener('click', () => { emit('goldenEgg:accept'); });
  $goldenEggPromptButtons.appendChild($yes);

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No';
  $no.addEventListener('click', () => { emit('goldenEgg:decline'); hideGoldenEggPrompt(); });
  $goldenEggPromptButtons.appendChild($no);

  $goldenEggPrompt.classList.remove('hidden');

  // Timer bar animation
  const elapsed = Date.now() - (startedAt || Date.now());
  const remaining = Math.max(0, (timeoutMs || 10000) - elapsed);
  const startFraction = remaining / (timeoutMs || 10000);
  $goldenEggTimerBar.style.transition = 'none';
  $goldenEggTimerBar.style.width = (startFraction * 100) + '%';
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      $goldenEggTimerBar.style.transition = `width ${remaining}ms linear`;
      $goldenEggTimerBar.style.width = '0%';
    });
  });
}

function hideGoldenEggPrompt() {
  goldenEggPromptShown = false;
  $goldenEggPrompt.classList.add('hidden');
  $goldenEggPromptButtons.innerHTML = '';
}

