const ORACLE_TYPES = ['Student', 'Familiar', 'Equip', 'Item', 'Spell', 'Snare'];
const ORACLE_TYPE_ICONS = { Student: '🎓', Familiar: '🐾', Equip: '⚔️', Item: '🧪', Spell: '✨', Snare: '🪤' };

function showOracleTypePicker() {
  const $btns = $oracleTypePicker.querySelector('.oracle-type-buttons');
  $btns.innerHTML = '';
  for (const type of ORACLE_TYPES) {
    const $b = document.createElement('button');
    $b.className = 'oracle-type-btn';
    $b.textContent = `${ORACLE_TYPE_ICONS[type]} ${type}`;
    $b.setAttribute('data-interactive', '');
    $b.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!targetingMode || targetingMode.effectType !== 'oracle-guess') return;
      targetingMode.chosenType = type;
      targetingMode.subPhase = 'select-opponent';
      hideOraclePickers();
      if (lastState) renderOpponents(lastState);
      updateTargetingUI();
    });
    $btns.appendChild($b);
  }
  $oracleTypePicker.classList.remove('hidden');
}

function hideOraclePickers() {
  $oracleTypePicker.classList.add('hidden');
}

function hideHocCardPicker() { /* no-op — HoC no longer uses an overlay */ }

// ── Magic Lamp overlay: shows full revealed hand of target opponent ───────
let _magicLampPickerEl = null;
function showMagicLampPicker(cards, opponentName) {
  hideMagicLampPicker();
  const $overlay = document.createElement('div');
  $overlay.className = 'magic-lamp-overlay';
  $overlay.innerHTML = `
    <div class="magic-lamp-panel">
      <div class="magic-lamp-title">🪔 ${opponentName}'s Hand — Choose a card to steal</div>
      <div class="magic-lamp-cards"></div>
    </div>`;
  const $cardsEl = $overlay.querySelector('.magic-lamp-cards');
  for (const c of cards) {
    const $card = document.createElement('div');
    $card.className = 'magic-lamp-card';
    $card.setAttribute('data-interactive', '');
    const $img = document.createElement('img');
    $img.src = c.path || '';
    $img.alt = c.name;
    $img.draggable = false;
    const $label = document.createElement('div');
    $label.className = 'magic-lamp-card-name';
    $label.textContent = c.name;
    $card.appendChild($img);
    $card.appendChild($label);
    $card.addEventListener('click', () => {
      if (!targetingMode || targetingMode.effectType !== 'magic-lamp-pick') return;
      emit('magicLamp:pickCard', { cardIndex: c.index });
      hideMagicLampPicker();
      targetingMode = null;
    });
    $cardsEl.appendChild($card);
  }
  document.body.appendChild($overlay);
  _magicLampPickerEl = $overlay;
}
function hideMagicLampPicker() {
  if (_magicLampPickerEl) { _magicLampPickerEl.remove(); _magicLampPickerEl = null; }
}

let oracleResultShown = false;

function updateOracleResult(state) {
  const or = state.oracleResult;
  if (or && !oracleResultShown) {
    oracleResultShown = true;
    const $type = $oracleResultOverlay.querySelector('.oracle-result-type');
    const $card = $oracleResultOverlay.querySelector('.oracle-result-card');
    const $verdict = $oracleResultOverlay.querySelector('.oracle-result-verdict');

    $type.textContent = `${or.guesserName} declared: ${ORACLE_TYPE_ICONS[or.chosenType] || ''} ${or.chosenType}`;

    if (or.card) {
      // Guesser sees the card
      $card.style.backgroundImage = `url("${cardImg(or.card)}")`;
      $card.classList.add('visible');
      setZoomable($card, cardImg(or.card));
    } else {
      $card.style.backgroundImage = '';
      $card.classList.remove('visible');
    }

    if (or.stolenCardName) {
      $verdict.textContent = `"${or.stolenCardName}" was taken by the whims of fate!`;
      $verdict.className = 'oracle-result-verdict oracle-stolen';
    } else if (or.correct) {
      $verdict.textContent = '✅ Correct! Card transferred!';
      $verdict.className = 'oracle-result-verdict oracle-correct';
    } else {
      $verdict.textContent = '❌ Wrong guess!';
      $verdict.className = 'oracle-result-verdict oracle-wrong';
    }

    $oracleResultOverlay.classList.remove('hidden');
  }
  if (!or && oracleResultShown) {
    oracleResultShown = false;
    $oracleResultOverlay.style.transition = 'opacity 0.8s ease';
    $oracleResultOverlay.style.opacity = '0';
    setTimeout(() => {
      $oracleResultOverlay.classList.add('hidden');
      $oracleResultOverlay.style.opacity = '';
      $oracleResultOverlay.style.transition = '';
    }, 900);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
//  GUARDIAN STATUE TRANSFER OVERLAY
// ═══════════════════════════════════════════════════════════════════════════

function showGuardianOverlay() {
  if (!targetingMode || targetingMode.effectType !== 'guardian-transfer' || !targetingMode.target) return;

  const tm = targetingMode;
  const maxTransfer = Math.min(tm.target.maxHp - tm.target.currentHp, tm.statueHp - 1);

  $guardianSourceCard.style.backgroundImage = `url("${tm.statuePath}")`;
  $guardianTargetCard.style.backgroundImage = `url("${tm.target.path}")`;

  $guardianSlider.min = 0;
  $guardianSlider.max = maxTransfer;
  $guardianSlider.value = 0;

  updateGuardianSliderDisplay(0);
  $guardianOverlay.classList.remove('hidden');
}

function hideGuardianOverlay() {
  $guardianOverlay.classList.add('hidden');
}

function updateGuardianSliderDisplay(val) {
  if (!targetingMode || !targetingMode.target) return;
  const tm = targetingMode;
  const v = parseInt(val) || 0;

  const srcHp = tm.statueHp - v;
  const tgtHp = tm.target.currentHp + v;

  $guardianSourceHp.textContent = `${srcHp} / ${tm.statueMaxHp}`;
  $guardianSourceHp.className = 'guardian-hp ' + (v > 0 ? 'hp-loss' : 'hp-neutral');

  $guardianTargetHp.textContent = `${tgtHp} / ${tm.target.maxHp}`;
  $guardianTargetHp.className = 'guardian-hp ' + (v > 0 ? 'hp-gain' : 'hp-neutral');

  $guardianSliderLabel.textContent = v > 0 ? `${v} HP` : '0 HP';
}

$guardianSlider.addEventListener('input', (e) => {
  updateGuardianSliderDisplay(e.target.value);
});

$guardianConfirm.addEventListener('click', () => {
  if (!targetingMode || targetingMode.effectType !== 'guardian-transfer' || !targetingMode.target) return;
  const amount = parseInt($guardianSlider.value) || 0;
  const t = targetingMode.target;
  emit('familiar:guardianTransfer', {
    targetPlayerId: t.playerId,
    targetType: t.type,
    targetFamiliarIndex: t.familiarIndex,
    amount,
  });
  hideGuardianOverlay();
  targetingMode = null;
});

function selectGuardianTarget(playerId, type, familiarIndex, currentHp, maxHp, path) {
  if (!targetingMode || targetingMode.effectType !== 'guardian-transfer') return;
  targetingMode.subPhase = 'slider';
  targetingMode.target = { playerId, type, familiarIndex, currentHp, maxHp, path };
  showGuardianOverlay();
  if (lastState) {
    renderMyBoard(lastState);
    renderOpponents(lastState);
  }
  updateTargetingUI();
}

