//  SNARE REACTION PROMPT
// ═══════════════════════════════════════════════════════════════════════════
let snarePromptTimerId = null;
let snarePromptShown = false;
let prevSnarePhase = null;

let jetpackPromptShown = false;
let jetpackDiscardMode = false; // true when player must pick a card to discard

function showSnarePrompt(sr) {
  if (snarePromptShown) return; // already showing
  snarePromptShown = true;

  const eligible = sr.eligibleSnares || [];
  $snarePromptButtons.innerHTML = '';

  // Show trigger context (e.g. which spell is being cast)
  const trigger = sr.trigger || {};
  let triggerInfo = null;
  let _studentAttackLabel = '';
  if (trigger.type === 'spell-cast-by-student' && trigger.spellName) {
    triggerInfo = document.createElement('div');
    triggerInfo.className = 'snare-trigger-info';
    const $spellRow = document.createElement('div');
    $spellRow.className = 'snare-trigger-spell-row';
    if (trigger.spellPath) {
      const $img = document.createElement('img');
      $img.className = 'snare-trigger-spell-img';
      $img.src = trigger.spellPath;
      $img.alt = trigger.spellName;
      setZoomable($img, trigger.spellPath);
      $spellRow.appendChild($img);
    }
    const $text = document.createElement('div');
    $text.className = 'snare-trigger-spell-text';
    $text.textContent = `${trigger.casterName || 'Opponent'} is casting "${trigger.spellName}"!`;
    $spellRow.appendChild($text);
    triggerInfo.appendChild($spellRow);
  } else if ((trigger.type === 'spell-resolving' || trigger.type === 'spell-multi-target' || trigger.type === 'targeting-spell-confirmed-by-student') && trigger.spellName) {
    triggerInfo = document.createElement('div');
    triggerInfo.className = 'snare-trigger-info';
    const $spellRow2 = document.createElement('div');
    $spellRow2.className = 'snare-trigger-spell-row';
    if (trigger.spellPath) {
      const $img = document.createElement('img');
      $img.className = 'snare-trigger-spell-img';
      $img.src = trigger.spellPath;
      $img.alt = trigger.spellName;
      setZoomable($img, trigger.spellPath);
      $spellRow2.appendChild($img);
    }
    const $text = document.createElement('div');
    $text.className = 'snare-trigger-spell-text';
    const cName = trigger.casterName || 'Opponent';
    const extra = trigger.targetName ? ` targeting "${trigger.targetName}"` : '';
    $text.textContent = `${cName} is casting "${trigger.spellName}"${extra}!`;
    $spellRow2.appendChild($text);
    triggerInfo.appendChild($spellRow2);
  } else if (trigger.type === 'item-used-by-opponent' && trigger.itemName) {
    triggerInfo = document.createElement('div');
    triggerInfo.className = 'snare-trigger-info';
    const $row = document.createElement('div');
    $row.className = 'snare-trigger-spell-row';
    if (trigger.itemPath) {
      const $img = document.createElement('img');
      $img.className = 'snare-trigger-spell-img';
      $img.src = trigger.itemPath;
      $img.alt = trigger.itemName;
      setZoomable($img, trigger.itemPath);
      $row.appendChild($img);
    }
    const $text2 = document.createElement('div');
    $text2.className = 'snare-trigger-spell-text';
    const sourcePlayer = (lastState?.others || []).find(o => o.id === trigger.sourcePlayerId);
    $text2.textContent = `${sourcePlayer?.name || 'Opponent'} is using "${trigger.itemName}"!`;
    $row.appendChild($text2);
    triggerInfo.appendChild($row);
  } else if (trigger.type === 'equip-landed-on-student' && trigger.cardName) {
    triggerInfo = document.createElement('div');
    triggerInfo.className = 'snare-trigger-info';
    const $row = document.createElement('div');
    $row.className = 'snare-trigger-spell-row';
    if (trigger.cardPath) {
      const $img = document.createElement('img');
      $img.className = 'snare-trigger-spell-img';
      $img.src = trigger.cardPath;
      $img.alt = trigger.cardName;
      setZoomable($img, trigger.cardPath);
      $row.appendChild($img);
    }
    const $text = document.createElement('div');
    $text.className = 'snare-trigger-spell-text';
    $text.textContent = `"${trigger.cardName}" is being equipped to ${trigger.targetPlayerName || 'a student'}!`;
    $row.appendChild($text);
    triggerInfo.appendChild($row);
  } else if (trigger.type === 'student-attack-confirmed' && trigger.attackerName) {
    // Don't create separate triggerInfo — it will be merged into the prompt title below
    _studentAttackLabel = `${trigger.attackerStudentName || 'Student'} is attacking! `;
  } else if (trigger.type === 'student-plays-card' && trigger.sourceName) {
    const verb = trigger.cardType === 'Spell' ? 'casting' : 'summoning';
    _studentAttackLabel = `${trigger.sourceStudentName || 'Student'} is ${verb} "${trigger.cardName}"! `;
  } else if (trigger.type === 'student-effect-activated' && trigger.sourceName) {
    _studentAttackLabel = `${trigger.sourceStudentName || 'Student'} is using its effect! `;
  } else if (trigger.type === 'player-would-win-by-escape' && trigger.winnerPlayerName) {
    _studentAttackLabel = `${trigger.winnerPlayerName} is about to escape! `;
  } else if (trigger.type === 'opponent-recovered-from-discard' && trigger.recoveryPlayerName) {
    _studentAttackLabel = `${trigger.recoveryPlayerName} recovered ${trigger.recoveryCount || 1} card(s)! `;
  } else if (trigger.type === 'round-start-equips') {
    _studentAttackLabel = `New round — enemies have Equips! `;
  }

  if (eligible.length === 1) {
    const costLabel = (eligible[0].cost || 0) > 0 ? ` (Cost: ${eligible[0].cost})` : '';
    if (_studentAttackLabel) {
      $snarePromptTitle.innerHTML = `${_studentAttackLabel}<br>Activate ${eligible[0].snareName}?${costLabel}`;
    } else {
      $snarePromptTitle.textContent = `Activate ${eligible[0].snareName}?${costLabel}`;
    }
    if (triggerInfo) $snarePromptButtons.appendChild(triggerInfo);
    if (eligible[0].hawkWouldNegate) {
      const $warn = document.createElement('div');
      $warn.className = 'snare-hawk-warning';
      $warn.textContent = '🦅 Moonlight Hawk would invalidate this Snare if you activate it now!';
      $snarePromptButtons.appendChild($warn);
    }
    const $yes = document.createElement('button');
    $yes.className = 'snare-prompt-btn snare-yes';
    $yes.textContent = 'Yes!';
    $yes.addEventListener('click', () => {
      emit('snare:activate', { snareIndex: eligible[0].snareIndex });
      hideSnarePrompt();
    });
    $snarePromptButtons.appendChild($yes);
  } else {
    if (_studentAttackLabel) {
      $snarePromptTitle.innerHTML = `${_studentAttackLabel}<br>Activate a Snare?`;
    } else {
      $snarePromptTitle.textContent = 'Activate a Snare?';
    }
    if (triggerInfo) $snarePromptButtons.appendChild(triggerInfo);
    for (const { snareIndex, snareName, hawkWouldNegate, cost } of eligible) {
      if (hawkWouldNegate) {
        const $warn = document.createElement('div');
        $warn.className = 'snare-hawk-warning';
        $warn.textContent = `🦅 Moonlight Hawk would invalidate ${snareName}!`;
        $snarePromptButtons.appendChild($warn);
      }
      const $btn = document.createElement('button');
      $btn.className = 'snare-prompt-btn snare-yes';
      const costLabel = (cost || 0) > 0 ? ` (Cost: ${cost})` : '';
      $btn.textContent = snareName + costLabel;
      $btn.addEventListener('click', () => {
        emit('snare:activate', { snareIndex });
        hideSnarePrompt();
      });
      $snarePromptButtons.appendChild($btn);
    }
  }

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No';
  $no.addEventListener('click', () => {
    emit('snare:decline');
    hideSnarePrompt();
  });
  $snarePromptButtons.appendChild($no);

  $snarePrompt.classList.remove('hidden');

  // Spell-interacting snares: highlight spell targets on the board
  const _highlightSnareNames = new Set(['Ghostly Warning', 'Book Trap', 'Anti Magic Shield', 'Anti Magic Zone', 'Jumpscare', 'Jungle Moat', 'Letter of Lies', 'Magic Mirror']);
  if (eligible.some(e => _highlightSnareNames.has(e.snareName))) {
    // Build highlight list from different trigger types
    let highlightTargets = [];
    if (sr.trigger) {
      const t = sr.trigger;
      if (t._highlightTargets && t._highlightTargets.length > 0) {
        // Instant spells (spell-cast-by-student): pre-computed potential targets
        highlightTargets = t._highlightTargets;
      } else if (t.affectedPlayers && t.affectedPlayers.length > 0) {
        // Targeting spells (spell-resolving / spell-multi-target): actual confirmed targets
        for (const ap of t.affectedPlayers) {
          for (const at of (ap.targets || [])) {
            highlightTargets.push({ playerId: ap.playerId, type: at.type, familiarIndex: at.familiarIndex ?? -1 });
          }
        }
      } else if (t.type === 'targeting-spell-confirmed-by-student' && t.targetPlayerId) {
        // Non-standard targets (equip, snare, fieldSpell — e.g. The Yeeting)
        highlightTargets.push({ playerId: t.targetPlayerId, type: t.targetType, index: t.targetIndex });
      }
    }
    const myId = lastState?.you?.id;
    for (const ht of highlightTargets) {
      let el = null;
      const isOwn = ht.playerId === myId;
      if (ht.type === 'student') {
        el = isOwn ? document.getElementById('my-student-slot')
          : document.querySelector(`.opponent-board-card[data-owner-id="${ht.playerId}"][data-target-type="student"]`);
      } else if (ht.type === 'familiar') {
        if (isOwn) {
          const all = [...(myFamLeftEls || []), ...(myFamRightEls || [])];
          const match = all.find(f => f.idx === (ht.familiarIndex ?? ht.index));
          if (match) el = match.el;
        } else {
          el = document.querySelector(`.opponent-board-card[data-owner-id="${ht.playerId}"][data-target-type="familiar"][data-familiar-index="${ht.familiarIndex ?? ht.index}"]`);
        }
      } else if (ht.type === 'equip') {
        el = isOwn ? document.querySelector(`#my-equip-row .my-equip-card:nth-child(${(ht.index ?? 0) + 1})`)
          : document.querySelector(`.opponent-board-card.is-equip[data-owner-id="${ht.playerId}"][data-equip-index="${ht.index}"]`);
      } else if (ht.type === 'snare') {
        if (isOwn) {
          const ownSnares = document.querySelectorAll('#my-snare-row .my-snare-card');
          el = ownSnares[ht.index ?? 0] || null;
        } else {
          el = document.querySelector(`.opponent-board-card.is-snare[data-owner-id="${ht.playerId}"][data-snare-index="${ht.index}"]`);
        }
      } else if (ht.type === 'fieldSpell') {
        if (isOwn) {
          const ownFS = document.querySelectorAll('.my-field-spell-card');
          el = ownFS[ht.index ?? 0] || null;
        } else {
          const oppFS = document.querySelectorAll(`.opponent-board-card.is-field-spell[data-owner-id="${ht.playerId}"]`);
          el = oppFS[ht.index ?? 0] || null;
        }
      }
      if (el) el.classList.add('snare-spell-highlight');
    }
  }

  // Timer bar animation — double-rAF for Firefox compatibility
  const elapsed = Date.now() - sr.startedAt;
  const remaining = Math.max(0, sr.timeoutMs - elapsed);
  const startFraction = remaining / sr.timeoutMs;
  $snarePromptTimerBar.style.transition = 'none';
  $snarePromptTimerBar.style.width = (startFraction * 100) + '%';
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      $snarePromptTimerBar.style.transition = `width ${remaining}ms linear`;
      $snarePromptTimerBar.style.width = '0%';
    });
  });
}

function hideSnarePrompt() {
  snarePromptShown = false;
  $snarePrompt.classList.add('hidden');
  $snarePromptButtons.innerHTML = '';
  if (snarePromptTimerId) { clearTimeout(snarePromptTimerId); snarePromptTimerId = null; }
  // Remove spell target highlights
  document.querySelectorAll('.snare-spell-highlight').forEach(el => el.classList.remove('snare-spell-highlight'));
}

