/**
 * Enter Chilly Wizzy spell selection targeting mode.
 * Shows eligible spells from hand for the player to pick.
 */
function enterCWSpellSelect() {
  const state = lastState;
  if (!state) return;
  const scr = state.you.spellCostReduction || 0;
  const mcp = state.you.manaCrystalPenalty || 0;
  const hand = state.you.hand || [];

  // Find eligible spell indices (affordable, castable, not blocked)
  const eligibleIndices = new Set();
  for (let i = 0; i < hand.length; i++) {
    const c = hand[i];
    if (c.type !== 'Spell') continue;
    if (state.noSpells) continue;
    if (state.plantGolemLock) continue;
    // Client-side cost calculation
    let cost = c.cost || 0;
    if (cost === -1) {
      // Variable cost: always affordable (can pay 0), check minCost against hand
      const minC = c.minCost ?? 1;
      if (minC > hand.length - 1) continue;
    } else {
      // Increase first (Crystal, Royalty, Corgi), then decrease (Chuunibyou, Chilly Wizzy)
      const royaltyInc = (state.you.royaltyStacks || 0) * 2;
      const corgiInc = state.you.corgiPenalty || 0;
      cost = cost + mcp + royaltyInc + corgiInc;
      if (scr > 0) cost = Math.max(0, cost - scr);
      if (c.chillyWizzyRevealed) cost = Math.max(0, cost - 3);
      if (cost > hand.length - 1) continue; // can't afford (spell itself leaves hand)
    }
    // Server-driven uncastable check (target requirements not met)
    if (c.spellUncastable) continue;
    eligibleIndices.add(i);
  }

  targetingMode = {
    effectType: 'cw-spell-select',
    canCancel: true,
    eligibleSpellIndices: eligibleIndices,
  };
  if (lastState) renderHand(lastState);
  updateTargetingUI();
}

/**
 * Enter Chilly Wizzy spell payment mode for a selected spell.
 */
function enterCWSpellPay(cardIndex) {
  const state = lastState;
  if (!state) return;
  const hand = state.you.hand || [];
  const spell = hand[cardIndex];
  if (!spell) return;

  const scr = state.you.spellCostReduction || 0;
  const mcp = state.you.manaCrystalPenalty || 0;
  let cost = spell.cost || 0;
  if (cost !== -1) {
    // Increase first (Crystal, Royalty, Corgi), then decrease
    const royaltyInc = (state.you.royaltyStacks || 0) * 2;
    const corgiInc = state.you.corgiPenalty || 0;
    cost = cost + mcp + royaltyInc + corgiInc;
    if (scr > 0) cost = Math.max(0, cost - scr);
    if (spell.chillyWizzyRevealed) cost = Math.max(0, cost - 3);
  }

  targetingMode = {
    effectType: 'cw-spell-pay',
    canCancel: true,
    selectedSpellIndex: cardIndex,
    spellCost: cost,
    selectedPayment: new Set(),
    spellName: spell.name,
    isVariableCost: cost === -1,
    minCost: (cost === -1) ? (spell.minCost ?? 1) : cost,
    maxCost: (cost === -1) ? (spell.maxCost != null ? spell.maxCost : Infinity) : cost,
  };
  // Dynamic cap for variable-cost spells based on board state
  if (cost === -1 && lastState) {
    if (spell.name === 'Frost Breaker') {
      const tapped = countTappedTargetsClient(lastState);
      targetingMode.maxCost = Math.max(0, tapped - 1);
    }
    if (spell.name === 'Book of Doom') {
      const targets = countBoardTargets(lastState);
      targetingMode.maxCost = Math.min(targetingMode.maxCost, targets);
      if (targetingMode.maxCost < 1) targetingMode.maxCost = 1;
    }
    if (spell.name === 'Smug Coin') {
      const discardSize = (lastState.you.discardPile || []).length;
      targetingMode.maxCost = Math.min(targetingMode.maxCost, discardSize);
      if (targetingMode.maxCost < 1) targetingMode.maxCost = 1;
    }
  }
  if (lastState) renderHand(lastState);
  updateTargetingUI();
}

