// ═══════════════════════════════════════════════════════════════════════════
//  THE PRODIGY — "Ignore this Cost?" prompt (client-side, 10s timer)
// ═══════════════════════════════════════════════════════════════════════════
const PRODIGY_TIMEOUT_MS = 10000;
let prodigyPromptTimer = null;

function showProdigyPrompt(cost, onAccept, onDecline) {
  hideProdigyPrompt(); // clear any existing

  $prodigyPromptTitle.textContent = cost === -1 ? 'Ignore this Variable Cost?' : `Ignore this Cost? (${cost})`;
  $prodigyPromptButtons.innerHTML = '';

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = 'Yes';
  $yes.addEventListener('click', () => { hideProdigyPrompt(); onAccept(); });

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No';
  $no.addEventListener('click', () => { hideProdigyPrompt(); onDecline(); });

  $prodigyPromptButtons.appendChild($yes);
  $prodigyPromptButtons.appendChild($no);

  // Timer bar animation
  $prodigyPromptTimerBar.style.transition = 'none';
  $prodigyPromptTimerBar.style.width = '100%';
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      $prodigyPromptTimerBar.style.transition = `width ${PRODIGY_TIMEOUT_MS}ms linear`;
      $prodigyPromptTimerBar.style.width = '0%';
    });
  });

  $prodigyPrompt.classList.remove('hidden');

  // Auto-decline on timeout
  prodigyPromptTimer = setTimeout(() => {
    hideProdigyPrompt();
    onDecline();
  }, PRODIGY_TIMEOUT_MS);
}

function hideProdigyPrompt() {
  if (prodigyPromptTimer) {
    clearTimeout(prodigyPromptTimer);
    prodigyPromptTimer = null;
  }
  $prodigyPrompt.classList.add('hidden');
  $prodigyPromptButtons.innerHTML = '';
}

