//  ELIXIR OF IMMORTALITY — client-side prompt + payment via discardMode
// ═══════════════════════════════════════════════════════════════════════════
let elixirPromptShown = false;

function showElixirPrompt(pe) {
  elixirPromptShown = true;
  $elixirPromptButtons.innerHTML = '';

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = 'Yes!';
  $yes.addEventListener('click', () => { emit('elixir:accept'); });

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No';
  $no.addEventListener('click', () => { hideElixirPrompt(); emit('elixir:decline'); });

  $elixirPromptButtons.appendChild($yes);
  $elixirPromptButtons.appendChild($no);

  // Timer bar
  const elapsed = Date.now() - (pe.startedAt || Date.now());
  const remaining = Math.max(0, (pe.timeoutMs || 15000) - elapsed);
  const startFraction = remaining / (pe.timeoutMs || 15000);
  $elixirPromptTimerBar.style.transition = 'none';
  $elixirPromptTimerBar.style.width = (startFraction * 100) + '%';
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      $elixirPromptTimerBar.style.transition = `width ${remaining}ms linear`;
      $elixirPromptTimerBar.style.width = '0%';
    });
  });

  $elixirPrompt.classList.remove('hidden');
}

function hideElixirPrompt() {
  elixirPromptShown = false;
  $elixirPrompt.classList.add('hidden');
  $elixirPromptButtons.innerHTML = '';
}

