function showSBREquipPicker(sbr) {
  sbrPickerShown = true;
  sbrSelectedEquip = null;
  $sbrEquipGrid.innerHTML = '';
  $sbrEquipConfirm.disabled = true;

  $sbrEquipDesc.textContent = `Choose an equip on ${sbr.attackerName}'s Student to destroy:`;

  sbr.equips.forEach(eq => {
    const $card = document.createElement('div');
    $card.className = 'sbr-equip-card';
    $card.style.backgroundImage = `url("${cardImg(eq)}")`;
    setZoomable($card, cardImg(eq));
    $card.setAttribute('data-interactive', '');
    $card.setAttribute('data-equip-index', eq.index);
    $card.addEventListener('click', (e) => {
      e.stopPropagation();
      document.querySelectorAll('.sbr-equip-card').forEach(c => c.classList.remove('sbr-equip-selected'));
      $card.classList.add('sbr-equip-selected');
      sbrSelectedEquip = eq.index;
      $sbrEquipConfirm.disabled = false;
    });
    $sbrEquipGrid.appendChild($card);
  });

  $sbrEquipConfirm.onclick = () => {
    if (sbrSelectedEquip === null) return;
    emit('swordBreakingRock:selectEquip', { equipIndex: sbrSelectedEquip });
    hideSBREquipPicker();
  };

  $sbrEquipPicker.classList.remove('hidden');
}

function hideSBREquipPicker() {
  sbrPickerShown = false;
  sbrSelectedEquip = null;
  $sbrEquipPicker.classList.add('hidden');
  $sbrEquipGrid.innerHTML = '';
}


// ═══════════════════════════════════════════════════════════════════════════
let energyCoreShown = false;
let energyCoreSelected = new Set(); // discard indices selected

function showEnergyCorePicker(discardPile) {
  energyCoreShown = true;
  energyCoreSelected = new Set();
  $energyCoreCards.innerHTML = '';

  discardPile.forEach((card, i) => {
    const $c = document.createElement('div');
    $c.className = 'energy-core-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (energyCoreSelected.has(i)) {
        energyCoreSelected.delete(i);
        $c.classList.remove('energy-core-selected');
      } else if (energyCoreSelected.size < 3) {
        energyCoreSelected.add(i);
        $c.classList.add('energy-core-selected');
      }
      const n = energyCoreSelected.size;
      $energyCoreCount.textContent = n;
      $energyCoreConfirmCount.textContent = n;
    });
    const $label = document.createElement('span');
    $label.className = 'energy-core-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $energyCoreCards.appendChild($c);
  });

  $energyCoreCount.textContent = '0';
  $energyCoreConfirmCount.textContent = '0';
  $energyCorePicker.classList.remove('hidden');
}

function hideEnergyCorePicker() {
  energyCoreShown = false;
  energyCoreSelected = new Set();
  $energyCorePicker.classList.add('hidden');
  $energyCoreCards.innerHTML = '';
}

$energyCoreConfirm.addEventListener('click', () => {
  if (!energyCoreShown) return;
  const selected = [...energyCoreSelected]; // capture BEFORE hideEnergyCorePicker clears the set
  hideEnergyCorePicker();
  emit('item:energyCoreConfirm', { discardIndices: selected });
});

$energyCoreSkip.addEventListener('click', () => {
  if (!energyCoreShown) return;
  hideEnergyCorePicker();
  emit('item:energyCoreConfirm', { discardIndices: [] });
});

// ═══════════════════════════════════════════════════════════════════════════
//  POTION OF GREED — Pick exactly 2 from own discard
// ═══════════════════════════════════════════════════════════════════════════
const $pogPicker      = document.getElementById('potion-of-greed-picker');
const $pogCards       = $pogPicker.querySelector('.potion-of-greed-picker-cards');
const $pogCount       = document.getElementById('potion-of-greed-count');
const $pogConfirm     = document.getElementById('potion-of-greed-confirm');
const $pogConfirmCount = document.getElementById('potion-of-greed-confirm-count');

let pogShown = false;
let pogSelected = new Set();

function showPotionOfGreedPicker(discardPile) {
  pogShown = true;
  pogSelected = new Set();
  $pogCards.innerHTML = '';

  discardPile.forEach((card, i) => {
    const $c = document.createElement('div');
    $c.className = 'energy-core-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      if (pogSelected.has(i)) {
        pogSelected.delete(i);
        $c.classList.remove('energy-core-selected');
      } else if (pogSelected.size < 2) {
        pogSelected.add(i);
        $c.classList.add('energy-core-selected');
      }
      const n = pogSelected.size;
      $pogCount.textContent = n;
      $pogConfirmCount.textContent = n;
      $pogConfirm.disabled = n !== 2;
    });
    const $label = document.createElement('span');
    $label.className = 'energy-core-picker-label';
    $label.textContent = card.name;
    $c.appendChild($label);
    $pogCards.appendChild($c);
  });

  $pogCount.textContent = '0';
  $pogConfirmCount.textContent = '0';
  $pogConfirm.disabled = true;
  $pogPicker.classList.remove('hidden');
}

function hidePotionOfGreedPicker() {
  pogShown = false;
  pogSelected = new Set();
  $pogPicker.classList.add('hidden');
  $pogCards.innerHTML = '';
}

$pogConfirm.addEventListener('click', () => {
  if (!pogShown || pogSelected.size !== 2) return;
  const selected = [...pogSelected];
  hidePotionOfGreedPicker();
  emit('potionOfGreed:confirm', { discardIndices: selected });
});


/**
 * shows the prompt. Otherwise proceeds directly to onPay().
 * @param {number} cost - the cost to potentially ignore
 * @param {Function} onIgnore - called if player accepts (emit with prodigyIgnoreCost: true)
 * @param {Function} onPay - called if player declines or not eligible (normal payment flow)
 */
// ═══════════════════════════════════════════════════════════════════════════
//  PICKAXE — "Skip discarding?" prompt (client-side, 10s timer, default Yes)
// ═══════════════════════════════════════════════════════════════════════════
const $pickaxePrompt          = document.getElementById('pickaxe-prompt');
const $pickaxePromptTimerBar  = $pickaxePrompt.querySelector('.pickaxe-prompt-timer-bar');
const $pickaxePromptButtons   = $pickaxePrompt.querySelector('.pickaxe-prompt-buttons');
const PICKAXE_TIMEOUT_MS = 10000;
let pickaxePromptTimer = null;

function showPickaxeSkipPrompt(onSkip, onDiscard) {
  hidePickaxeSkipPrompt();

  $pickaxePromptButtons.innerHTML = '';

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = 'Skip!';
  $yes.addEventListener('click', () => { hidePickaxeSkipPrompt(); onSkip(); });

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'Discard';
  $no.addEventListener('click', () => { hidePickaxeSkipPrompt(); onDiscard(); });

  $pickaxePromptButtons.appendChild($yes);
  $pickaxePromptButtons.appendChild($no);

  // Timer bar — fills then auto-accepts (Skip)
  $pickaxePromptTimerBar.style.transition = 'none';
  $pickaxePromptTimerBar.style.width = '100%';
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      $pickaxePromptTimerBar.style.transition = `width ${PICKAXE_TIMEOUT_MS}ms linear`;
      $pickaxePromptTimerBar.style.width = '0%';
    });
  });

  $pickaxePrompt.classList.remove('hidden');

  // Auto-skip on timeout
  pickaxePromptTimer = setTimeout(() => {
    hidePickaxeSkipPrompt();
    onSkip();
  }, PICKAXE_TIMEOUT_MS);
}

function hidePickaxeSkipPrompt() {
  if (pickaxePromptTimer) {
    clearTimeout(pickaxePromptTimer);
    pickaxePromptTimer = null;
  }
  $pickaxePrompt.classList.add('hidden');
  $pickaxePromptButtons.innerHTML = '';
}

