// ═══════════════════════════════════════════════════════════════════════════
//  POTION LAUNCHER — "Use an Item from discard?" + item select + payment
// ═══════════════════════════════════════════════════════════════════════════
const $potionLauncherPrompt         = document.getElementById('potion-launcher-prompt');
const $potionLauncherTimerBar       = $potionLauncherPrompt.querySelector('.potion-launcher-prompt-timer-bar');
const $potionLauncherPromptButtons  = $potionLauncherPrompt.querySelector('.potion-launcher-prompt-buttons');
const $potionLauncherSelect         = document.getElementById('potion-launcher-select');
const $potionLauncherSelectCards    = $potionLauncherSelect.querySelector('.revive-picker-cards');
const $potionLauncherSelectCancel   = document.getElementById('potion-launcher-select-cancel');
const POTION_LAUNCHER_PROMPT_MS_CLIENT = 10000;
let potionLauncherPromptTimer = null;
let potionLauncherPromptShown = false;

function showPotionLauncherPrompt() {
  if (potionLauncherPromptShown) return;
  potionLauncherPromptShown = true;
  $potionLauncherPromptButtons.innerHTML = '';

  const $yes = document.createElement('button');
  $yes.className = 'snare-prompt-btn snare-yes';
  $yes.textContent = 'Yes!';
  $yes.addEventListener('click', () => { hidePotionLauncherPrompt(); emit('potionLauncher:accept'); });

  const $no = document.createElement('button');
  $no.className = 'snare-prompt-btn snare-no';
  $no.textContent = 'No';
  $no.addEventListener('click', () => { hidePotionLauncherPrompt(); emit('potionLauncher:skip'); });

  $potionLauncherPromptButtons.appendChild($yes);
  $potionLauncherPromptButtons.appendChild($no);

  $potionLauncherTimerBar.style.transition = 'none';
  $potionLauncherTimerBar.style.width = '100%';
  requestAnimationFrame(() => requestAnimationFrame(() => {
    $potionLauncherTimerBar.style.transition = `width ${POTION_LAUNCHER_PROMPT_MS_CLIENT}ms linear`;
    $potionLauncherTimerBar.style.width = '0%';
  }));

  $potionLauncherPrompt.classList.remove('hidden');
  potionLauncherPromptTimer = setTimeout(() => {
    hidePotionLauncherPrompt();
    emit('potionLauncher:skip');
  }, POTION_LAUNCHER_PROMPT_MS_CLIENT);
}

function hidePotionLauncherPrompt() {
  potionLauncherPromptShown = false;
  if (potionLauncherPromptTimer) { clearTimeout(potionLauncherPromptTimer); potionLauncherPromptTimer = null; }
  $potionLauncherPrompt.classList.add('hidden');
  $potionLauncherPromptButtons.innerHTML = '';
}

function showPotionLauncherSelect(eligibleItems) {
  $potionLauncherSelectCards.innerHTML = '';
  const discardPile = lastState?.you?.discardPile || [];
  for (const item of eligibleItems) {
    const card = discardPile[item.discardIndex];
    if (!card) continue; // safety: card no longer at that index
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(card)}")`;
    setZoomable($c, cardImg(card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      hidePotionLauncherSelect();
      emit('potionLauncher:selectItem', { discardIndex: item.discardIndex });
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    const costLabel = item.isVariableCost ? 'Variable cost' : (item.cost === 0 ? 'Free' : `Cost: ${item.cost}`);
    $label.textContent = `${card.name} — ${costLabel}`;
    $c.appendChild($label);
    $potionLauncherSelectCards.appendChild($c);
  }
  $potionLauncherSelect.classList.remove('hidden');
}

function hidePotionLauncherSelect() {
  $potionLauncherSelect.classList.add('hidden');
  $potionLauncherSelectCards.innerHTML = '';
}

$potionLauncherSelectCancel.addEventListener('click', () => {
  hidePotionLauncherSelect();
  emit('potionLauncher:cancelSelect');
});

// ── Copy Device item picker ─────────────────────────────────────────────
const $copyDeviceSelect      = document.getElementById('copy-device-select');
const $copyDeviceSelectCards = $copyDeviceSelect.querySelector('.copy-device-select-cards');
const $copyDeviceSelectCancel = document.getElementById('copy-device-select-cancel');
let copyDeviceSelectShown = false;

function showCopyDeviceSelect(eligibleItems) {
  if (copyDeviceSelectShown) return;
  copyDeviceSelectShown = true;
  $copyDeviceSelectCards.innerHTML = '';
  for (const item of eligibleItems) {
    const $c = document.createElement('div');
    $c.className = 'revive-picker-card';
    $c.style.backgroundImage = `url("${cardImg(item.card)}")`;
    setZoomable($c, cardImg(item.card));
    $c.setAttribute('data-interactive', '');
    $c.addEventListener('click', (e) => {
      e.stopPropagation();
      hideCopyDeviceSelect();
      emit('copyDevice:selectItem', { ownerId: item.ownerId, discardIndex: item.discardIndex });
    });
    const $label = document.createElement('span');
    $label.className = 'revive-picker-label';
    $label.textContent = `${item.card.name} (${item.ownerName})`;
    $c.appendChild($label);
    $copyDeviceSelectCards.appendChild($c);
  }
  $copyDeviceSelect.classList.remove('hidden');
}

function hideCopyDeviceSelect() {
  if (!copyDeviceSelectShown) return;
  copyDeviceSelectShown = false;
  $copyDeviceSelect.classList.add('hidden');
  $copyDeviceSelectCards.innerHTML = '';
}

function cancelCopyDevice() {
  hideCopyDeviceSelect();
  emit('copyDevice:cancel');
}

$copyDeviceSelectCancel.addEventListener('click', cancelCopyDevice);

function attemptProdigyCostIgnore(cost, onIgnore, onPay) {
  if (lastState && lastState.you.prodigyChargeReady && lastState.phase === 'exam' && (cost > 0 || cost === -1)) {
    showProdigyPrompt(cost, onIgnore, onPay);
  } else {
    onPay();
  }
}

function showSnareFlipAnimation(state) {
  const sr = state.snareReaction;
  if (!sr || sr.phase !== 'flipping') return;

  const ownerId = sr.activatedPlayerId;
  const snareIdx = sr.activatedSnareIndex;

  // Find snare DOM element — own snares or opponent snares
  let $snareEl = null;
  if (ownerId === state.you.id) {
    const snareEls = document.querySelectorAll('#my-snare-row .my-snare-card');
    if (snareEls[snareIdx]) $snareEl = snareEls[snareIdx];
  } else {
    const oppEls = document.querySelectorAll(`.opponent-board-card.is-snare[data-owner-id="${ownerId}"]`);
    if (oppEls[snareIdx]) $snareEl = oppEls[snareIdx];
  }

  if (!$snareEl || $snareEl.classList.contains('snare-flipping')) return;

  $snareEl.classList.add('snare-flipping');

  // At midpoint (400ms), swap the image to face-up
  setTimeout(() => {
    const snareName = sr.activatedSnareName;
    if (snareName && ownerId === state.you.id) {
      const snare = state.you.snares[snareIdx];
      if (snare && snare.faceUp) {
        $snareEl.style.backgroundImage = `url("${cardImg(snare)}")`;
      }
    } else {
      const opp = state.others.find(o => o.id === ownerId);
      if (opp && opp.snares && opp.snares[snareIdx] && opp.snares[snareIdx].faceUp) {
        $snareEl.style.backgroundImage = `url("${cardImg(opp.snares[snareIdx])}")`;
      }
    }
  }, 400);

  // ── Shockwave ring ──
  const $shockwave = document.createElement('div');
  $shockwave.className = 'snare-shockwave';
  $snareEl.style.position = 'relative';
  $snareEl.appendChild($shockwave);
  setTimeout(() => $shockwave.remove(), 1200);

  // ── Particle burst — 24 particles in two rings ──
  const $particles = document.createElement('div');
  $particles.className = 'snare-flip-particles';
  const colors = ['#ff6030','#ffaa00','#ff4444','#ffcc00','#fff','#ff8800','#ffd700','#ff5555'];
  for (let i = 0; i < 24; i++) {
    const $p = document.createElement('div');
    $p.className = 'snare-flip-particle';
    const angle = (i / 24) * Math.PI * 2 + (Math.random() - 0.5) * 0.3;
    const ring = i < 12 ? 1 : 2;
    const dist = ring === 1 ? (35 + Math.random() * 30) : (60 + Math.random() * 40);
    const size = ring === 1 ? (4 + Math.random() * 4) : (3 + Math.random() * 3);
    $p.style.setProperty('--px', Math.cos(angle) * dist + 'px');
    $p.style.setProperty('--py', Math.sin(angle) * dist + 'px');
    $p.style.left = '50%';
    $p.style.top = '50%';
    $p.style.width = size + 'px';
    $p.style.height = size + 'px';
    $p.style.background = colors[i % colors.length];
    $p.style.animationDelay = (ring === 2 ? 0.1 : 0) + 's';
    $particles.appendChild($p);
  }
  $snareEl.appendChild($particles);
  setTimeout(() => $particles.remove(), 1200);

  // ── Full-screen flash ──
  const $flash = document.createElement('div');
  $flash.className = 'snare-screen-flash';
  document.body.appendChild($flash);
  setTimeout(() => $flash.remove(), 600);

  // ── Floating name banner ──
  if (sr.activatedSnareName) {
    const rect = $snareEl.getBoundingClientRect();
    const $banner = document.createElement('div');
    $banner.className = 'snare-name-banner';
    $banner.textContent = `🪤 ${sr.activatedSnareName}!`;
    $banner.style.left = (rect.left + rect.width / 2) + 'px';
    $banner.style.top = (rect.top - 10) + 'px';
    document.body.appendChild($banner);
    setTimeout(() => $banner.remove(), 2000);
  }
}

/** Show jaws animations for all clients using old DOM positions (before re-render) */
function showJawsAnimations(state) {
  const events = state.jawsEvents || [];
  if (events.length === 0) return;

  for (const evt of events) {
    let $snareEl = null;
    if (evt.playerId === state.you.id) {
      const ownSnares = document.querySelectorAll('#my-snare-row .my-snare-card');
      $snareEl = ownSnares[evt.snareIndex];
    } else {
      $snareEl = document.querySelector(`.opponent-board-card.is-snare[data-owner-id="${evt.playerId}"][data-snare-index="${evt.snareIndex}"]`);
    }
    if (!$snareEl) continue;
    playJawsAnimation($snareEl.getBoundingClientRect());
  }
}

/**
 * Rocket Fist: explosion animation on the destroyed Snare.
 * Uses old DOM positions (snapshotted before re-render).
 */
function showRocketFistAnimation(state) {
  const events = state.rocketFistEvents || [];
  if (events.length === 0) return;

  for (const evt of events) {
    let $snareEl = null;
    if (evt.playerId === state.you.id) {
      const ownSnares = document.querySelectorAll('#my-snare-row .my-snare-card');
      $snareEl = ownSnares[evt.snareIndex];
    } else {
      $snareEl = document.querySelector(`.opponent-board-card.is-snare[data-owner-id="${evt.playerId}"][data-snare-index="${evt.snareIndex}"]`);
    }
    if (!$snareEl) continue;

    const rect = $snareEl.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;

    // Fist emoji slam-in
    const $fist = document.createElement('div');
    $fist.textContent = '🚀✊';
    $fist.style.cssText = `
      position: fixed;
      left: ${cx}px;
      top: ${cy - 60}px;
      font-size: 2.4rem;
      transform: translate(-50%, -50%);
      pointer-events: none;
      z-index: 9999;
      animation: rocketFistSlam 0.22s ease-in forwards;
    `;
    document.body.appendChild($fist);

    // Explosion after fist arrives
    setTimeout(() => {
      $fist.remove();
      const $container = document.createElement('div');
      $container.className = 'bomb-explosion-container';
      $container.style.left = cx + 'px';
      $container.style.top  = cy + 'px';

      const $boom = document.createElement('div');
      $boom.className = 'snare-explosion';
      $container.appendChild($boom);

      for (let i = 0; i < 16; i++) {
        const $spark = document.createElement('div');
        $spark.className = 'snare-explosion-spark';
        const angle = (i / 16) * Math.PI * 2;
        const dist = 40 + Math.random() * 40;
        $spark.style.setProperty('--sx', Math.cos(angle) * dist + 'px');
        $spark.style.setProperty('--sy', Math.sin(angle) * dist + 'px');
        $spark.style.left = '50%';
        $spark.style.top  = '50%';
        $spark.style.background = ['#ff6030','#ffcc00','#fff','#ff8800'][i % 4];
        $container.appendChild($spark);
      }

      document.body.appendChild($container);
      setTimeout(() => $container.remove(), 900);
    }, 200);
  }
}

/**
 * Shield of Death: dark magic skull burst at the targeted Familiar.
 * Uses pre-snapshotted coords so it fires at the right spot even if
 * the Familiar died and was removed from the DOM.
 */
function showShieldOfDeathAnimation(coords) {
  if (!coords || coords.length === 0) return;
  for (const { cx, cy } of coords) {
    const $container = document.createElement('div');
    $container.style.cssText = `
      position: fixed;
      left: ${cx}px;
      top: ${cy}px;
      width: 0;
      height: 0;
      pointer-events: none;
      z-index: 9999;
    `;

    // Dark pulsing core
    const $core = document.createElement('div');
    $core.style.cssText = `
      position: absolute;
      left: -28px; top: -28px;
      width: 56px; height: 56px;
      border-radius: 50%;
      background: radial-gradient(circle, #6a0dad 0%, #1a0030 60%, transparent 100%);
      animation: sodCorePulse 0.55s ease-out forwards;
    `;
    $container.appendChild($core);

    // Orbiting skulls
    const skullCount = 6;
    for (let i = 0; i < skullCount; i++) {
      const $skull = document.createElement('div');
      const angle = (i / skullCount) * Math.PI * 2;
      const dist = 30 + Math.random() * 22;
      const delay = (i / skullCount) * 0.18;
      const dur = 0.5 + Math.random() * 0.25;
      $skull.textContent = '💀';
      $skull.style.cssText = `
        position: absolute;
        left: 50%; top: 50%;
        font-size: ${0.9 + Math.random() * 0.5}rem;
        transform: translate(-50%, -50%);
        pointer-events: none;
        animation: sodSkullBurst ${dur}s ease-out ${delay}s forwards;
        opacity: 0;
        --bx: ${Math.cos(angle) * dist}px;
        --by: ${Math.sin(angle) * dist}px;
      `;
      $container.appendChild($skull);
    }

    // Purple sparks
    for (let i = 0; i < 12; i++) {
      const $spark = document.createElement('div');
      const angle = (i / 12) * Math.PI * 2 + Math.random() * 0.4;
      const dist = 25 + Math.random() * 35;
      $spark.style.cssText = `
        position: absolute;
        left: 50%; top: 50%;
        width: ${3 + Math.random() * 4}px;
        height: ${3 + Math.random() * 4}px;
        border-radius: 50%;
        background: ${['#9b30ff','#bf5fff','#6a0dad','#e040fb','#ce93d8'][i % 5]};
        transform: translate(-50%,-50%);
        animation: sodSparkFly 0.6s ease-out ${Math.random() * 0.15}s forwards;
        --sx: ${Math.cos(angle) * dist}px;
        --sy: ${Math.sin(angle) * dist}px;
        opacity: 0;
      `;
      $container.appendChild($spark);
    }

    document.body.appendChild($container);
    setTimeout(() => $container.remove(), 900);
  }
}

/**
 * Shield of Life: holy light burst at the healed Familiar.
 */
function showShieldOfLifeAnimation(coords) {
  if (!coords || coords.length === 0) return;
  for (const { cx, cy } of coords) {
    const $container = document.createElement('div');
    $container.style.cssText = `
      position: fixed; left: ${cx}px; top: ${cy}px;
      width: 0; height: 0; pointer-events: none; z-index: 9999;
    `;

    // Golden radiant core
    const $core = document.createElement('div');
    $core.style.cssText = `
      position: absolute; left: -32px; top: -32px;
      width: 64px; height: 64px; border-radius: 50%;
      background: radial-gradient(circle, #fffde7 0%, #ffd54f 40%, #fff9c4 70%, transparent 100%);
      animation: solCoreBurst 0.6s ease-out forwards;
    `;
    $container.appendChild($core);

    // Shockwave ring
    const $ring = document.createElement('div');
    $ring.style.cssText = `
      position: absolute; left: -40px; top: -40px;
      width: 80px; height: 80px; border-radius: 50%;
      border: 3px solid #ffe082;
      animation: solRingExpand 0.55s ease-out forwards;
    `;
    $container.appendChild($ring);

    // Flying sparkles
    const sparkColors = ['#fff9c4','#ffd54f','#ffe082','#ffecb3','#ffffff'];
    for (let i = 0; i < 14; i++) {
      const $spark = document.createElement('div');
      const angle = (i / 14) * Math.PI * 2 + Math.random() * 0.3;
      const dist = 28 + Math.random() * 32;
      const delay = Math.random() * 0.18;
      const size = 4 + Math.random() * 5;
      $spark.style.cssText = `
        position: absolute; left: 50%; top: 50%;
        width: ${size}px; height: ${size}px; border-radius: 50%;
        background: ${sparkColors[i % sparkColors.length]};
        box-shadow: 0 0 4px 2px rgba(255,220,80,0.7);
        transform: translate(-50%,-50%);
        animation: solSparkFly 0.65s ease-out ${delay}s forwards;
        --sx: ${Math.cos(angle) * dist}px; --sy: ${Math.sin(angle) * dist}px;
        opacity: 0;
      `;
      $container.appendChild($spark);
    }

    // ✨ emoji cross
    const $star = document.createElement('div');
    $star.textContent = '✨';
    $star.style.cssText = `
      position: absolute; left: 50%; top: 50%;
      font-size: 1.8rem; transform: translate(-50%,-50%);
      animation: solStarPop 0.5s ease-out forwards;
      pointer-events: none; opacity: 0;
    `;
    $container.appendChild($star);

    document.body.appendChild($container);
    setTimeout(() => $container.remove(), 900);
  }
}

/**
 * Escape Rope: spin-fade the targeted snare element.
 * Hides the original immediately (no overlap), clones it to a fixed-position
 * overlay on document.body and animates it independently of board re-renders.
 * Always returns false so normal renders proceed unaffected.
 */
function showEscapeRopeAnimation(state) {
  const evt = state.escapeRopeEvent;
  if (!evt) return false;

  let $snareEl = null;
  if (evt.playerId === state.you.id) {
    const ownSnares = document.querySelectorAll('#my-snare-row .my-snare-card');
    $snareEl = ownSnares[evt.snareIndex] || null;
  } else {
    $snareEl = document.querySelector(`.opponent-board-card.is-snare[data-owner-id="${evt.playerId}"][data-snare-index="${evt.snareIndex}"]`);
  }
  if (!$snareEl) return false;

  const rect = $snareEl.getBoundingClientRect();
  if (rect.width === 0 && rect.height === 0) return false;

  // Hide original immediately — no overlap with the spinning clone
  $snareEl.style.visibility = 'hidden';

  // Clone into a fixed overlay on document.body, independent of any re-renders
  const $clone = $snareEl.cloneNode(true);
  const bgImage = $snareEl.style.backgroundImage;  // preserve inline bg before any style reset
  // Keep only the base appearance class — strip all game-logic classes (targeting, selection,
  // immunity badges, etc.) so CSS rules like .snare-destroyable.target-selected{animation:none}
  // can't suppress the spin-fade animation on the activating player's clone.
  const isOwn = evt.playerId === state.you.id;
  $clone.className = isOwn ? 'my-snare-card' : 'opponent-board-card is-snare';
  $clone.style.cssText = '';  // wipe all copied inline styles
  $clone.style.position = 'fixed';
  $clone.style.left = rect.left + 'px';
  $clone.style.top = rect.top + 'px';
  $clone.style.width = rect.width + 'px';
  $clone.style.height = rect.height + 'px';
  $clone.style.margin = '0';
  $clone.style.visibility = 'visible';
  $clone.style.opacity = '1';
  $clone.style.zIndex = '9998';
  $clone.style.pointerEvents = 'none';
  $clone.style.transformOrigin = 'center center';
  $clone.style.backgroundImage = bgImage;  // re-apply the card image
  $clone.classList.add('escape-rope-spin-fade');
  document.body.appendChild($clone);

  setTimeout(() => $clone.remove(), 1500);

  return false;  // always allow normal re-renders
}

/** Flashbang: fullscreen white-out blast that fades quickly */
// ── Gathering Storm ambient weather effect ────────────────────────────
let _stormInterval = null;

function isGatheringStormActive() {
  if (!lastState) return false;
  const allPlayers = [lastState.you, ...(lastState.others || [])];
  return allPlayers.some(p => p && !p.left && (p.fieldSpells || []).some(fs => fs.name === 'Gathering Storm'));
}

function spawnStormCloud() {
  const $c = document.createElement('div');
  $c.className = 'storm-cloud';
  const w = 220 + Math.random() * 300;
  const h = 80 + Math.random() * 120;
  const top = Math.random() * (window.innerHeight * 0.75);
  const dur = 6 + Math.random() * 6;
  const delay = Math.random() * 1.5;
  const driftY = (Math.random() - 0.5) * 30;
  $c.style.cssText += `width:${w}px;height:${h}px;top:${top}px;left:0;
    --cloud-dur:${dur}s;--cloud-delay:${delay}s;--cloud-drift-y:${driftY}px;`;
  document.body.appendChild($c);
  setTimeout(() => $c.remove(), (dur + delay + 0.5) * 1000);
}

function spawnLightningStrike() {
  // Screen flash
  const $flash = document.createElement('div');
  $flash.className = 'storm-lightning-flash';
  const flashDur = 0.35 + Math.random() * 0.25;
  $flash.style.setProperty('--flash-dur', flashDur + 's');
  document.body.appendChild($flash);
  setTimeout(() => $flash.remove(), (flashDur + 0.1) * 1000);

  // Bolt
  const $bolt = document.createElement('div');
  $bolt.className = 'storm-lightning-bolt';
  const boltH = 80 + Math.random() * 180;
  const boltX = window.innerWidth * (0.1 + Math.random() * 0.8);
  const boltTop = Math.random() * (window.innerHeight * 0.4);
  const boltDur = 0.45 + Math.random() * 0.25;
  const tilt = (Math.random() - 0.5) * 30;
  $bolt.style.cssText += `left:${boltX}px;top:${boltTop}px;height:${boltH}px;
    --bolt-dur:${boltDur}s;transform:rotate(${tilt}deg);`;
  document.body.appendChild($bolt);
  setTimeout(() => $bolt.remove(), (boltDur + 0.1) * 1000);
}

function tickStormEffects() {
  if (!isGatheringStormActive()) return;
  const r = Math.random();
  if (r < 0.45) spawnStormCloud();
  else if (r < 0.75) spawnLightningStrike();
  else { spawnStormCloud(); spawnLightningStrike(); }
}

function scheduleNextStormTick() {
  if (!_stormInterval) return; // cancelled
  const delay = 1400 + Math.random() * 2000;
  _stormInterval = setTimeout(() => {
    if (!isGatheringStormActive()) {
      _stormInterval = null;
      return;
    }
    tickStormEffects();
    scheduleNextStormTick();
  }, delay);
}

function updateGatheringStorm() {
  const active = isGatheringStormActive();
  if (active && !_stormInterval) {
    // Immediate burst then recurring random ticks
    spawnStormCloud(); spawnStormCloud(); spawnLightningStrike();
    _stormInterval = true; // sentinel so scheduleNextStormTick doesn't bail immediately
    scheduleNextStormTick();
  } else if (!active && _stormInterval) {
    clearTimeout(_stormInterval);
    _stormInterval = null;
  }
}

function showCosmicBalanceAnimation(state) {
  const evt = state.cosmicBalanceEvent;
  if (!evt) return;
  const key = evt.eventId;
  if (!key || showCosmicBalanceAnimation._lastKey === key) return;
  showCosmicBalanceAnimation._lastKey = key;
  clearTimeout(showCosmicBalanceAnimation._clearTimer);
  showCosmicBalanceAnimation._clearTimer = setTimeout(() => { showCosmicBalanceAnimation._lastKey = null; }, 6000);

  const $el = document.createElement('div');
  $el.className = 'cosmic-balance-overlay';
  $el.textContent = '⚖️';
  document.body.appendChild($el);
  setTimeout(() => $el.remove(), 2800);
}

function showConfusingMelodyAnimation(state) {
  const events = state.confusingMelodyEvent;
  if (!events || !events.length) return;
  if (!showConfusingMelodyAnimation._lastLen) showConfusingMelodyAnimation._lastLen = 0;
  // Simple guard: only fire if list length changed (new cast)
  const key = events.length + ':' + (events[0]?.playerId || '');
  if (showConfusingMelodyAnimation._lastKey === key) return;
  showConfusingMelodyAnimation._lastKey = key;
  setTimeout(() => { showConfusingMelodyAnimation._lastKey = null; }, 5000);

  const SYMBOLS = ['🎵', '🎶', '⭐', '💫', '🌀', '❓', '😵'];

  for (const evt of events) {
    const el = document.querySelector(
      `[data-owner-id="${evt.playerId}"][data-target-type="familiar"][data-familiar-index="${evt.familiarIndex}"]`
    );
    if (!el) continue;
    const rect = el.getBoundingClientRect();
    if (rect.width === 0) continue;
    for (let i = 0; i < 5; i++) {
      const $p = document.createElement('div');
      $p.className = 'confuse-particle';
      $p.textContent = SYMBOLS[Math.floor(Math.random() * SYMBOLS.length)];
      const sx = rect.left + Math.random() * rect.width;
      const sy = rect.top + Math.random() * rect.height;
      const dx = (Math.random() - 0.5) * 60;
      const dy = -40 - Math.random() * 60;
      const rot = (Math.random() - 0.5) * 360;
      const dur = 1.0 + Math.random() * 0.8;
      const delay = i * 0.1 + Math.random() * 0.15;
      $p.style.left = sx + 'px';
      $p.style.top = sy + 'px';
      $p.style.setProperty('--cf-dx', dx + 'px');
      $p.style.setProperty('--cf-dy', dy + 'px');
      $p.style.setProperty('--cf-rot', rot + 'deg');
      $p.style.setProperty('--cf-dur', dur + 's');
      $p.style.setProperty('--cf-delay', delay + 's');
      document.body.appendChild($p);
      setTimeout(() => $p.remove(), (dur + delay + 0.2) * 1000);
    }
  }
}

function showColdCoffinAnimations(state) {
  const events = state.coldCoffinEvent;
  if (!events || !events.length) return;
  for (const evt of events) {
    const key = evt.eventId;
    if (!key) continue;
    if (!showColdCoffinAnimations._seen) showColdCoffinAnimations._seen = new Set();
    if (showColdCoffinAnimations._seen.has(key)) continue;
    showColdCoffinAnimations._seen.add(key);
    setTimeout(() => showColdCoffinAnimations._seen?.delete(key), 8000);

    // Find the target familiar element — works for both own and opponent boards
    const targetEl = document.querySelector(
      `[data-owner-id="${evt.playerId}"][data-target-type="familiar"][data-familiar-index="${evt.familiarIndex}"]`
    );
    if (!targetEl) continue;

    const rect = targetEl.getBoundingClientRect();
    if (rect.width === 0) continue;

    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;

    // Glow pulse behind the card
    const $glow = document.createElement('div');
    $glow.className = 'cold-coffin-glow';
    $glow.style.left = (rect.left - 6) + 'px';
    $glow.style.top = (rect.top - 6) + 'px';
    $glow.style.width = (rect.width + 12) + 'px';
    $glow.style.height = (rect.height + 12) + 'px';
    document.body.appendChild($glow);
    setTimeout(() => $glow.remove(), 2200);

    // 8 ice panels covering the card at different rotations / stagger
    const PANELS = 8;
    const HOLD_MS = 1200;
    const SHATTER_MS = 1700;
    for (let i = 0; i < PANELS; i++) {
      const $p = document.createElement('div');
      $p.className = 'cold-coffin-panel';
      const rot = (Math.random() - 0.5) * 30;
      const w = rect.width * (0.35 + Math.random() * 0.5);
      const h = rect.height * (0.35 + Math.random() * 0.5);
      const ox = (Math.random() - 0.5) * rect.width * 0.6;
      const oy = (Math.random() - 0.5) * rect.height * 0.6;
      const delay = (i / PANELS) * 0.5;
      const dx = (Math.random() - 0.5) * 120;
      const dy = -40 - Math.random() * 80;
      $p.style.left = (cx + ox) + 'px';
      $p.style.top = (cy + oy) + 'px';
      $p.style.width = w + 'px';
      $p.style.height = h + 'px';
      $p.style.setProperty('--ice-rot', rot + 'deg');
      $p.style.setProperty('--ice-delay', delay + 's');
      $p.style.setProperty('--ice-shatter', (HOLD_MS / 1000 + delay) + 's');
      $p.style.setProperty('--ice-dx', dx + 'px');
      $p.style.setProperty('--ice-dy', dy + 'px');
      document.body.appendChild($p);
      setTimeout(() => $p.remove(), (SHATTER_MS + delay * 1000 + 700));
    }

    // A few crack lines radiating from center
    for (let i = 0; i < 5; i++) {
      const $cr = document.createElement('div');
      $cr.className = 'cold-coffin-crack';
      const angle = (i / 5) * 180 + (Math.random() - 0.5) * 20;
      const len = 20 + Math.random() * (rect.height * 0.5);
      const delay = 0.2 + i * 0.06;
      $cr.style.left = cx + 'px';
      $cr.style.top = cy + 'px';
      $cr.style.height = len + 'px';
      $cr.style.transform = `rotate(${angle}deg)`;
      $cr.style.setProperty('--ice-rot', angle + 'deg');
      $cr.style.setProperty('--ice-delay', delay + 's');
      $cr.style.setProperty('--ice-shatter', (HOLD_MS / 1000 + 0.1) + 's');
      $cr.style.setProperty('--ice-dx', (Math.random() - 0.5) * 40 + 'px');
      $cr.style.setProperty('--ice-dy', (-20 - Math.random() * 40) + 'px');
      document.body.appendChild($cr);
      setTimeout(() => $cr.remove(), SHATTER_MS + 700);
    }
  }
}

