function showMeteorAnimation(state) {
  const evt = state.meteorEvent;
  if (!evt || _meteorShown) return;
  _meteorShown = true;
  setTimeout(() => { _meteorShown = false; }, 100);

  // Snapshot all field spell cards currently on the DOM and hold them as
  // position:fixed ghosts until the moment of impact, so they only disappear
  // when the meteor actually hits — not when the state update arrives.
  const IMPACT_MS = 560; // matches meteorFall delay(0.1s) + duration(0.5s) at ~80%
  const fieldSpellEls = document.querySelectorAll('.my-field-spell-card, .opponent-board-card.is-field-spell');
  const ghosts = [];
  for (const el of fieldSpellEls) {
    const rect = el.getBoundingClientRect();
    if (rect.width === 0 && rect.height === 0) continue;
    const bgImage = el.style.backgroundImage;
    if (!bgImage) continue;
    const $ghost = document.createElement('div');
    $ghost.style.cssText = `
      position: fixed;
      left: ${rect.left}px;
      top: ${rect.top}px;
      width: ${rect.width}px;
      height: ${rect.height}px;
      margin: 0;
      z-index: 99998;
      pointer-events: none;
      border-radius: 8px;
      background-image: ${bgImage};
      background-size: cover;
      background-position: center;
      border: 2px solid rgba(255,200,50,0.6);
      box-shadow: 0 2px 8px rgba(0,0,0,0.4), 0 0 12px rgba(255,200,50,0.2);
      transition: opacity 0.15s ease-out;
    `;
    document.body.appendChild($ghost);
    ghosts.push($ghost);
  }
  // Flash-remove ghosts at impact with a brief shake
  setTimeout(() => {
    for (const g of ghosts) {
      g.style.opacity = '0';
      setTimeout(() => g.remove(), 200);
    }
  }, IMPACT_MS);

  const $overlay = document.createElement('div');
  $overlay.className = 'meteor-overlay';

  // The meteor itself falling from top-center
  const $meteor = document.createElement('div');
  $meteor.className = 'meteor-rock';
  $overlay.appendChild($meteor);

  // Shockwave ring at impact
  const $shockwave = document.createElement('div');
  $shockwave.className = 'meteor-shockwave';
  $overlay.appendChild($shockwave);

  // Title
  const $title = document.createElement('div');
  $title.className = 'meteor-title';
  $title.textContent = '☄️ METEOR!';
  $overlay.appendChild($title);

  // Subtitle
  const $sub = document.createElement('div');
  $sub.className = 'meteor-subtitle';
  $sub.textContent = 'All Field Spells destroyed!';
  $overlay.appendChild($sub);

  // Debris chunks flying out from center
  for (let i = 0; i < 24; i++) {
    const $chunk = document.createElement('div');
    $chunk.className = 'meteor-debris';
    const angle = (i / 24) * Math.PI * 2 + (Math.random() - 0.5) * 0.5;
    const dist = 80 + Math.random() * 160;
    $chunk.style.setProperty('--dx', Math.cos(angle) * dist + 'px');
    $chunk.style.setProperty('--dy', Math.sin(angle) * dist + 'px');
    $chunk.style.animationDelay = (0.35 + Math.random() * 0.15) + 's';
    $chunk.style.width = (6 + Math.random() * 12) + 'px';
    $chunk.style.height = $chunk.style.width;
    $overlay.appendChild($chunk);
  }

  // Dust plume particles
  for (let i = 0; i < 16; i++) {
    const $dust = document.createElement('div');
    $dust.className = 'meteor-dust';
    $dust.style.left = (30 + Math.random() * 40) + '%';
    $dust.style.animationDelay = (0.4 + Math.random() * 0.3) + 's';
    $overlay.appendChild($dust);
  }

  document.body.appendChild($overlay);

  setTimeout(() => {
    $overlay.classList.add('meteor-fade');
    setTimeout(() => $overlay.remove(), 800);
  }, 2800);
}

