// ═══════════════════════════════════════════════════════════════════════════
//  ACTIVE SPELL DISPLAY (shown to ALL players for ~2 seconds)
// ═══════════════════════════════════════════════════════════════════════════
let activeSpellShown = null;
let spellDismissTimer = null;
let spellFadeTimer = null;
let stolenSnareShown = false;

function showActiveSpell(card, playerName, casterId, state, sourceCard = null) {
  if (spellDismissTimer) { clearTimeout(spellDismissTimer); spellDismissTimer = null; }
  if (spellFadeTimer)    { clearTimeout(spellFadeTimer);    spellFadeTimer    = null; }

  // If I'm the caster, skip — I already know what I'm resolving
  if (state && casterId && casterId === state.you.id) return;

  // Anchor above the caster's student card element
  let anchorEl = null;
  if (casterId) {
    anchorEl = document.querySelector(`[data-owner-id="${casterId}"][data-target-type="student"]`);
  }
  if (!anchorEl) return; // caster has no student on board — nothing to anchor to

  const rect = anchorEl.getBoundingClientRect();
  const isItem     = card.type === 'Item';
  const isEquip    = card.type === 'Equip';
  const isFamiliar = card.type === 'Familiar';
  const isPassive  = !!card.passiveEffect;
  const labelText  = isPassive ? 'Passive' : isItem ? 'Item' : isEquip ? 'Equip' : isFamiliar ? 'Discard' : 'Spell';

  const cardW = Math.round(rect.width  * 1.5);
  const cardH = Math.round(rect.height * 1.5);

  if (sourceCard) {
    // Two-card layout: source (Mystery Box) on the left, spell on the right, centred together
    const gap = 8;
    const totalW = cardW * 2 + gap;
    const centerX = rect.left + rect.width / 2;

    // Source card (Mystery Box)
    const $src = document.createElement('div');
    $src.className = 'floating-spell-card floating-spell-source';
    $src.style.left   = `${centerX - totalW / 2}px`;
    $src.style.top    = `${rect.top}px`;
    $src.style.width  = `${cardW}px`;
    $src.style.height = `${cardH}px`;
    $src.style.backgroundImage = `url("${cardImg(sourceCard)}")`;
    $src.dataset.label = 'Item';
    document.body.appendChild($src);
    $src.addEventListener('animationend', () => $src.remove());
    setTimeout(() => { if ($src.parentNode) $src.remove(); }, 3200);

    // Spell card
    const $wrap = document.createElement('div');
    $wrap.className = 'floating-spell-card';
    $wrap.style.left   = `${centerX - totalW / 2 + cardW + gap}px`;
    $wrap.style.top    = `${rect.top}px`;
    $wrap.style.width  = `${cardW}px`;
    $wrap.style.height = `${cardH}px`;
    $wrap.style.backgroundImage = `url("${cardImg(card)}")`;
    $wrap.dataset.label = labelText;
    document.body.appendChild($wrap);
    $wrap.addEventListener('animationend', () => $wrap.remove());
    setTimeout(() => { if ($wrap.parentNode) $wrap.remove(); }, 3200);
  } else {
    const $wrap = document.createElement('div');
    $wrap.className = 'floating-spell-card';
    $wrap.style.left   = `${rect.left + rect.width / 2}px`;
    $wrap.style.top    = `${rect.top}px`;
    $wrap.style.width  = `${cardW}px`;
    $wrap.style.height = `${cardH}px`;
    $wrap.style.backgroundImage = `url("${cardImg(card)}")`;
    $wrap.dataset.label = labelText;
    document.body.appendChild($wrap);
    $wrap.addEventListener('animationend', () => $wrap.remove());
    setTimeout(() => { if ($wrap.parentNode) $wrap.remove(); }, 3200);
  }
}

function hideActiveSpell() {
  if (spellDismissTimer) { clearTimeout(spellDismissTimer); spellDismissTimer = null; }
  if (spellFadeTimer)    { clearTimeout(spellFadeTimer);    spellFadeTimer    = null; }
  $spellOverlay.classList.add('hidden');
  $spellOverlay.style.opacity = '';
  $spellOverlay.style.transition = '';
  activeSpellShown = null;
  stolenSnareShown = false;
}

// ═══════════════════════════════════════════════════════════════════════════
//  ZOOM SYSTEM (with click-to-lock)
// ═══════════════════════════════════════════════════════════════════════════
let zoomLocked = false;     // is the zoom preview locked?
let zoomLockedSrc = null;   // the locked image src

function setZoomable(el, imagePath) {
  if (imagePath) el.dataset.zoomSrc = imagePath;
  else delete el.dataset.zoomSrc;
}

function showZoom(src, cloneName) {
  $zoomImg.src = src;
  $zoom.classList.remove('hidden');
  if (cloneName) {
    $zoomCloneLabel.textContent = '🧬 ' + cloneName;
    $zoomCloneLabel.classList.remove('hidden');
  } else {
    $zoomCloneLabel.classList.add('hidden');
  }
}

function hideZoom() {
  $zoom.classList.add('hidden');
}

function unlockZoom() {
  zoomLocked = false;
  zoomLockedSrc = null;
  $zoom.classList.remove('zoom-locked');
  // Immediately update to whatever is under cursor (or hide)
  const hovered = document.querySelector('[data-zoom-src]:hover');
  if (hovered) {
    showZoom(hovered.dataset.zoomSrc, hovered.dataset.cloneName || null);
  } else {
    hideZoom();
  }
}

// Hover: show zoom (only if not locked)
document.addEventListener('mouseenter', (e) => {
  if (zoomLocked) return;
  if (!(e.target instanceof Element)) return;
  const el = e.target.closest('[data-zoom-src]');
  if (!el) return;
  showZoom(el.dataset.zoomSrc, el.dataset.cloneName || null);
}, true);

document.addEventListener('mouseleave', (e) => {
  if (zoomLocked) return;
  if (!(e.target instanceof Element)) return;
  const el = e.target.closest('[data-zoom-src]');
  if (!el) return;
  // If the cursor is moving to another element still inside this same card, don't hide
  if (e.relatedTarget instanceof Element && el.contains(e.relatedTarget)) return;
  hideZoom();
}, true);

// Click on zoomable: lock (or update if already locked to different card)
// SKIP zoom-lock for: discard piles (data-no-zoom-lock), interactive cards (data-interactive)
document.addEventListener('click', (e) => {
  const el = e.target.closest('[data-zoom-src]');
  if (el && !el.hasAttribute('data-no-zoom-lock') && !el.hasAttribute('data-interactive')) {
    const src = el.dataset.zoomSrc;
    if (zoomLocked && zoomLockedSrc === src) {
      // Clicking same locked card — unpin
      unlockZoom();
      return;
    }
    // Lock to this card
    zoomLocked = true;
    zoomLockedSrc = src;
    showZoom(src, el.dataset.cloneName || null);
    $zoom.classList.add('zoom-locked');
    return;
  }
  // Clicked on non-zoomable area or interactive/discard element: unlock
  if (zoomLocked) {
    unlockZoom();
  }
}, true);

// Touch support
document.addEventListener('touchstart', (e) => {
  const el = e.target.closest('[data-zoom-src]');
  if (el) {
    e.preventDefault();
    const src = el.dataset.zoomSrc;
    zoomLocked = true;
    zoomLockedSrc = src;
    showZoom(src, el.dataset.cloneName || null);
    $zoom.classList.add('zoom-locked');
  } else if (zoomLocked) {
    unlockZoom();
  }
}, { capture: true, passive: false });

// ═══════════════════════════════════════════════════════════════════════════
//  BADGE TOOLTIP
// ═══════════════════════════════════════════════════════════════════════════
// A single floating div (position:fixed, appended to body) that escapes all
// overflow:hidden contexts. Shown next to any .status-badge[data-tooltip]
// on mouseenter, hidden on mouseleave. Completely independent from zoom logic.

const $badgeTip = document.createElement('div');
$badgeTip.id = 'badge-tooltip';
$badgeTip.className = 'badge-tooltip';
$badgeTip.style.display = 'none';
document.body.appendChild($badgeTip);

document.addEventListener('mouseenter', (e) => {
  if (!(e.target instanceof Element)) return;
  const badge = e.target.closest('.status-badge[data-tooltip]');
  if (!badge) return;
  const tip = badge.dataset.tooltip;
  if (!tip) return;
  $badgeTip.textContent = tip;
  $badgeTip.style.display = 'block';
  const r = badge.getBoundingClientRect();
  // Position to the right of the badge; flip left if near right edge
  let x = r.right + 6;
  const tipW = $badgeTip.offsetWidth || 180;
  if (x + tipW > window.innerWidth - 8) x = r.left - tipW - 6;
  $badgeTip.style.left = x + 'px';
  $badgeTip.style.top = Math.max(0, r.top - 2) + 'px';
}, true);

document.addEventListener('mouseleave', (e) => {
  if (!(e.target instanceof Element)) return;
  const badge = e.target.closest('.status-badge[data-tooltip]');
  if (!badge) return;
  $badgeTip.style.display = 'none';
}, true);

