      const sel = targetingMode.selected;
      const isSteroidSelected = sel && sel.familiarIndex === idx;
      el.classList.toggle('target-selected', isSteroidSelected);
      el.classList.add('bless-candidate');
      el.setAttribute('data-interactive', '');
