function showCharmAnimations(state) {
  const events = state.charmEvents;
  if (!events || events.length === 0) return;

  for (const evt of events) {
    // Collect target elements for both new and old positions
    const targets = [];

    // New position (where the familiar ended up)
    if (evt.playerId === state.you.id) {
      const all = [...myFamLeftEls, ...myFamRightEls];
      const match = all.find(f => f.idx === evt.familiarIndex);
      if (match) targets.push(match.el);
    } else {
      const el = document.querySelector(`[data-owner-id="${evt.playerId}"][data-target-type="familiar"][data-familiar-index="${evt.familiarIndex}"]`);
      if (el) targets.push(el);
    }

    // Old position (opponent who lost the familiar — use their student as anchor)
    if (evt.fromPlayerId === state.you.id) {
      if ($studentSlot) targets.push($studentSlot);
    } else {
      const el = document.querySelector(`[data-owner-id="${evt.fromPlayerId}"][data-target-type="student"]`)
        || document.querySelector(`[data-owner-id="${evt.fromPlayerId}"]`);
      if (el) targets.push(el);
    }

    for (const targetEl of targets) {
      const rect = targetEl.getBoundingClientRect();
      const cx = rect.left + rect.width / 2;
      const cy = rect.top + rect.height / 2;

      const isDarkGear = !!evt.darkGear;
      for (let i = 0; i < 6; i++) {
        const $heart = document.createElement('div');
        $heart.className = isDarkGear ? 'floating-charm-heart dark-gear-spin' : 'floating-charm-heart';
        $heart.textContent = isDarkGear ? '⚙️' : '💖';
        const offsetX = (Math.random() - 0.5) * rect.width * 1.2;
        const delay = Math.random() * 0.4;
        $heart.style.left = `${cx + offsetX}px`;
        $heart.style.top = `${cy}px`;
        $heart.style.animationDelay = `${delay}s`;
        document.body.appendChild($heart);
        $heart.addEventListener('animationend', () => $heart.remove());
        setTimeout(() => { if ($heart.parentNode) $heart.remove(); }, 3000);
      }
    }
  }
}

