function showWerzSwapAnimations(state) {
  const events = state.werzSwapEvents;
  if (!events || events.length === 0) return;

  for (const evt of events) {
    // Own hand: show 🎁 on the card you received
    let cardIndex = -1;
    if (state.you.id === evt.activatorId) cardIndex = evt.activatorCardIndex;
    else if (state.you.id === evt.targetId) cardIndex = evt.targetCardIndex;

    if (cardIndex >= 0) {
      const handCards = [...document.querySelectorAll('#hand-cards .hand-card')];
      const targetEl = handCards[cardIndex];
      if (targetEl) showWerzGiftOnElement(targetEl);
    }
  }
}

function showArmsTradeSwapAnimations(state) {
  const events = state.armsTradeSwapEvents;
  if (!events || events.length === 0) return;

  function getEquipEl(playerId, equipIndex) {
    if (playerId === state.you.id) {
      return document.querySelector(`#my-equip-row .my-equip-card:nth-child(${equipIndex + 1})`);
    }
    return document.querySelector(`.opponent-board-card.is-equip[data-owner-id="${playerId}"][data-equip-index="${equipIndex}"]`);
  }

  for (const evt of events) {
    const elA = getEquipEl(evt.playerIdA, evt.equipIndexA);
    const elB = getEquipEl(evt.playerIdB, evt.equipIndexB);
    if (!elA || !elB) continue;

    const rectA = elA.getBoundingClientRect();
    const rectB = elB.getBoundingClientRect();
    if (rectA.width === 0 || rectB.width === 0) continue;

    const bgA = getComputedStyle(elA).backgroundImage;
    const bgB = getComputedStyle(elB).backgroundImage;

    // Clone A flies to B's position
    const $flyA = document.createElement('div');
    $flyA.className = 'arms-trade-fly-card';
    $flyA.style.backgroundImage = bgA;
    $flyA.style.left = `${rectA.left}px`;
    $flyA.style.top = `${rectA.top}px`;
    $flyA.style.width = `${rectA.width}px`;
    $flyA.style.height = `${rectA.height}px`;
    document.body.appendChild($flyA);

    // Clone B flies to A's position
    const $flyB = document.createElement('div');
    $flyB.className = 'arms-trade-fly-card';
    $flyB.style.backgroundImage = bgB;
    $flyB.style.left = `${rectB.left}px`;
    $flyB.style.top = `${rectB.top}px`;
    $flyB.style.width = `${rectB.width}px`;
    $flyB.style.height = `${rectB.height}px`;
    document.body.appendChild($flyB);

    // Trigger fly on next frame — double rAF for Firefox transition reliability
    requestAnimationFrame(() => requestAnimationFrame(() => {
      $flyA.style.left = `${rectB.left}px`;
      $flyA.style.top = `${rectB.top}px`;
      $flyA.style.width = `${rectB.width}px`;
      $flyA.style.height = `${rectB.height}px`;
      $flyB.style.left = `${rectA.left}px`;
      $flyB.style.top = `${rectA.top}px`;
      $flyB.style.width = `${rectA.width}px`;
      $flyB.style.height = `${rectA.height}px`;
    }));

    setTimeout(() => { $flyA.remove(); $flyB.remove(); }, 700);
  }
}

function showEquipAnimations(state) {
  const events = state.equipEvents;
  if (!events || events.length === 0) return;
  for (const evt of events) {
    const count = evt.count || 1;
    let cards;
    if (evt.playerId === state.you.id) {
      cards = [...document.querySelectorAll('#my-equip-row .my-equip-card')];
    } else {
      cards = [...document.querySelectorAll(`.opponent-board-card.is-equip[data-owner-id="${evt.playerId}"]`)];
    }
    // Highlight the last N cards (the newly equipped ones)
    const startIdx = Math.max(0, cards.length - count);
    for (let i = startIdx; i < cards.length; i++) {
      const $el = cards[i];
      if ($el) {
        $el.classList.add('equip-glow');
        setTimeout(() => $el.classList.remove('equip-glow'), 1500);
      }
    }
  }
}

