function showControlDeviceAnimations(state) {
  const playRing = (ownerId, familiarIndex, cssClass) => {
    let el;
    if (ownerId === state.you.id) {
      // Own board: familiar cards render in order inside #my-familiars-left / right
      const allOwn = [
        ...($famLeft  ? $famLeft.querySelectorAll('.my-familiar-card')  : []),
        ...($famRight ? $famRight.querySelectorAll('.my-familiar-card') : []),
      ];
      el = allOwn[familiarIndex] || null;
    } else {
      el = document.querySelector(`[data-owner-id="${ownerId}"][data-target-type="familiar"][data-familiar-index="${familiarIndex}"]`);
    }
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;

    const $container = document.createElement('div');
    $container.className = 'bomb-explosion-container';
    $container.style.left = cx + 'px';
    $container.style.top = cy + 'px';

    const $ring = document.createElement('div');
    $ring.className = cssClass;
    $container.appendChild($ring);

    document.body.appendChild($container);
    setTimeout(() => $container.remove(), 900);
  };

  for (const evt of (state.controlDeviceStealEvents || [])) {
    playRing(evt.thiefId, evt.familiarIndex, 'control-device-steal-ring');
  }
  for (const evt of (state.controlDeviceReturnEvents || [])) {
    playRing(evt.originalOwnerId, evt.familiarIndex, 'control-device-return-ring');
  }
}

function showProphecyDamageAnimations(state) {
  const events = state.prophecyDamageEvents;
  if (!events || events.length === 0) return;

  // Animate each affected student with a dark purple shadowy pulse
  const seen = new Set();
  for (const evt of events) {
    if (seen.has(evt.playerId)) continue; // one animation per player even if multiple instances
    seen.add(evt.playerId);

    let $el;
    if (evt.playerId === state.you.id) {
      $el = $studentSlot;
    } else {
      $el = document.querySelector(`[data-owner-id="${evt.playerId}"][data-target-type="student"]`);
    }
    if (!$el) continue;

    const rect = $el.getBoundingClientRect();
    const $container = document.querySelector('.bomb-explosion-container') || (() => {
      const c = document.createElement('div');
      c.className = 'bomb-explosion-container';
      document.body.appendChild(c);
      return c;
    })();

    const $anim = document.createElement('div');
    $anim.className = 'prophecy-damage-pulse';
    $anim.style.left = `${rect.left + rect.width / 2}px`;
    $anim.style.top = `${rect.top + rect.height / 2}px`;
    $container.appendChild($anim);
    $anim.addEventListener('animationend', () => $anim.remove(), { once: true });
  }
}

function showCharmOfBalanceAnimation(state) {
  const evt = state.charmOfBalanceEvent;
  if (!evt) return;

  // Helper: find the student element for a given playerId
  const getStudentEl = (pid) => {
    if (pid === state.you.id) return $studentSlot;
    return document.querySelector(`[data-owner-id="${pid}"][data-target-type="student"]`);
  };

  for (const pid of [evt.sourcePlayerId, evt.targetPlayerId]) {
    const el = getStudentEl(pid);
    if (!el) continue;
    const rect = el.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;

    const $container = document.createElement('div');
    $container.className = 'bomb-explosion-container';
    $container.style.left = cx + 'px';
    $container.style.top = cy + 'px';

    const $pulse = document.createElement('div');
    $pulse.className = 'charm-balance-pulse';
    $container.appendChild($pulse);

    document.body.appendChild($container);
    setTimeout(() => $container.remove(), 900);
  }
}

// ── Doomsday Bomb prompt & explosion ─────────────────────────────────────

let $doomsdayOverlay = null;

function showDoomsdayBombPrompt(ddb) {
  if ($doomsdayOverlay) return; // already shown
  $doomsdayOverlay = document.createElement('div');
  $doomsdayOverlay.className = 'pending-prompt-overlay'; // reuse the modal overlay style
  $doomsdayOverlay.innerHTML = `
    <div class="pending-prompt-box doomsday-prompt-box">
      <div class="doomsday-prompt-title">💣 Doomsday Bomb</div>
      <div class="doomsday-prompt-body">
        <span class="doomsday-counter-display">${ddb.doomCounters} Doom Counter${ddb.doomCounters !== 1 ? 's' : ''}</span><br>
        Detonate for <strong>${ddb.damage} damage</strong> to ALL targets?
      </div>
      <div class="doomsday-prompt-buttons">
        <button class="doomsday-btn-yes" id="doomsday-yes">💥 DETONATE!</button>
        <button class="doomsday-btn-no" id="doomsday-no">✋ No</button>
      </div>
    </div>
  `;
  document.body.appendChild($doomsdayOverlay);

  $doomsdayOverlay.querySelector('#doomsday-yes').addEventListener('click', () => {
    emit('doomsdayBomb:confirm');
    hideDoomsdayBombPrompt();
  });
  $doomsdayOverlay.querySelector('#doomsday-no').addEventListener('click', () => {
    emit('doomsdayBomb:cancel');
    hideDoomsdayBombPrompt();
  });
}

function hideDoomsdayBombPrompt() {
  if ($doomsdayOverlay) {
    $doomsdayOverlay.remove();
    $doomsdayOverlay = null;
  }
}

function showDoomsdayExplosion(state) {
  const evt = state.doomsdayExplosionEvent;
  if (!evt) return;

  const $overlay = document.createElement('div');
  $overlay.className = 'doomsday-explosion-overlay';
  const $text = document.createElement('div');
  $text.className = 'doomsday-explosion-text';
  $text.innerHTML = `💥 DOOMSDAY BOMB 💥<br>-${evt.damage} to ALL`;
  $overlay.appendChild($text);
  document.body.appendChild($overlay);
  $overlay.addEventListener('animationend', () => $overlay.remove(), { once: true });
  setTimeout(() => { if ($overlay.parentNode) $overlay.remove(); }, 2000);
}

