/** Flame Fairy Statue — big engulfing flame column per target, position-locked */
function showFlameFairyStatueAnimation(coords) {
  if (!coords || coords.length === 0) return;
  for (const { cx, cy, w, h } of coords) {
    const fw = Math.max(60, (w || 60) * 1.1);
    const fh = Math.max(90, (h || 80) * 1.6);

    const $container = document.createElement('div');
    $container.className = 'ffs-flame-container';
    $container.style.left  = (cx - fw / 2) + 'px';
    $container.style.top   = (cy - fh * 0.75) + 'px';
    $container.style.width  = fw + 'px';
    $container.style.height = fh + 'px';

    // Glow behind the flames
    const $glow = document.createElement('div');
    $glow.className = 'ffs-flame-glow';
    $container.appendChild($glow);

    // Main tongue flames (5 rising columns)
    for (let i = 0; i < 5; i++) {
      const $tongue = document.createElement('div');
      $tongue.className = 'ffs-flame-tongue';
      const xPos = 10 + i * 18;  // percent
      const dur  = 0.55 + Math.random() * 0.3;
      const delay = i * 0.07 + Math.random() * 0.08;
      const hScale = 0.7 + Math.random() * 0.6;
      $tongue.style.left = xPos + '%';
      $tongue.style.animationDuration  = dur + 's';
      $tongue.style.animationDelay = delay + 's';
      $tongue.style.setProperty('--fh', hScale);
      const hue = Math.random() < 0.4 ? '#ffcc00' : (Math.random() < 0.5 ? '#ff6600' : '#ff3300');
      $tongue.style.background = `radial-gradient(ellipse at 50% 80%, ${hue} 0%, rgba(255,80,0,0.7) 50%, transparent 100%)`;
      $container.appendChild($tongue);
    }

    // Small dancing sparks
    for (let i = 0; i < 12; i++) {
      const $spark = document.createElement('div');
      $spark.className = 'ffs-flame-spark';
      $spark.style.left  = (10 + Math.random() * 80) + '%';
      $spark.style.bottom = (5 + Math.random() * 30) + '%';
      $spark.style.animationDelay = (Math.random() * 0.5) + 's';
      $spark.style.animationDuration = (0.4 + Math.random() * 0.4) + 's';
      const sAngle = (Math.random() - 0.5) * 60;
      const sDist  = 20 + Math.random() * 35;
      $spark.style.setProperty('--sax', Math.sin(sAngle * Math.PI / 180) * sDist + 'px');
      $spark.style.setProperty('--say', -sDist + 'px');
      $container.appendChild($spark);
    }

    document.body.appendChild($container);
    setTimeout(() => $container.remove(), 1400);
  }
}

