// ── Bottled Lightning animation helpers ──────────────────────────────────

function _getTargetCoords(target, state) {
  if (!target) return null;
  const el = findTargetElement(target.playerId, target.type, target.familiarIndex, state);
  if (!el) return null;
  const rect = el.getBoundingClientRect();
  return { x: rect.left + rect.width / 2, y: rect.top + rect.height / 2, rect };
}

function _snapshotBottledLightningPositions(pbl, state) {
  // p0 = caster's student (bolt origin), p1 = target1, p2 = target2, p3 = counterTarget
  // caster may be "you" or an opponent from this client's perspective
  const casterStudentEl = findTargetElement(pbl.casterId, 'student', -1, state);
  if (!casterStudentEl) return null;
  const r0 = casterStudentEl.getBoundingClientRect();
  const coords = {
    p0: { x: r0.left + r0.width / 2, y: r0.top + r0.height / 2 },
    p1: _getTargetCoords(pbl.target1, state),
    p2: _getTargetCoords(pbl.target2, state),
    p3: pbl.counterTarget ? _getTargetCoords(pbl.counterTarget, state) : null,
  };
  return coords.p1 && coords.p2 ? coords : null;
}

function _spawnLightningImpact(tx, ty, tRect) {
  for (let i = 0; i < 10; i++) {
    const $shard = document.createElement('div');
    $shard.className = 'lightning-burst-shard';
    const ang = (Math.PI * 2 * i / 10) + (Math.random() - 0.5) * 0.4;
    const dist = 18 + Math.random() * 28;
    $shard.style.left = tx + 'px';
    $shard.style.top  = ty + 'px';
    $shard.style.setProperty('--sx', (Math.cos(ang) * dist) + 'px');
    $shard.style.setProperty('--sy', (Math.sin(ang) * dist) + 'px');
    $shard.style.animationDelay = (Math.random() * 0.04) + 's';
    document.body.appendChild($shard);
    setTimeout(() => { if ($shard.parentNode) $shard.remove(); }, 700);
  }
  if (tRect) {
    const $glow = document.createElement('div');
    $glow.className = 'lightning-impact-glow';
    $glow.style.left   = tRect.left + 'px';
    $glow.style.top    = tRect.top + 'px';
    $glow.style.width  = tRect.width + 'px';
    $glow.style.height = tRect.height + 'px';
    document.body.appendChild($glow);
    setTimeout(() => { if ($glow.parentNode) $glow.remove(); }, 1000);
  }
}

function _fireLightningBolt(boltIndex, pbl, state, isCaster) {
  const pos = bottledLightningPositions;
  if (!pos) return;
  const fromTo = [
    { from: pos.p0, to: pos.p1, targetRef: pbl.target1 },
    { from: pos.p1, to: pos.p2, targetRef: pbl.target2 },
    { from: pos.p2, to: pos.p3, targetRef: pbl.counterTarget },
  ];
  const { from, to } = fromTo[boltIndex] || {};
  if (!from || !to) {
    // Nothing to animate — signal landed immediately
    emit('bottledLightning:boltLanded', { boltIndex });
    return;
  }

  const dx = to.x - from.x;
  const dy = to.y - from.y;
  const angle = Math.atan2(dy, dx) * (180 / Math.PI);
  const dist  = Math.sqrt(dx * dx + dy * dy);
  const flightMs = Math.min(450, Math.max(200, dist * 0.75));

  const $bolt = document.createElement('div');
  $bolt.className = 'lightning-bolt';
  $bolt.style.left = from.x + 'px';
  $bolt.style.top  = from.y + 'px';
  $bolt.style.setProperty('--dx', dx + 'px');
  $bolt.style.setProperty('--dy', dy + 'px');
  $bolt.style.setProperty('--angle', angle + 'deg');
  $bolt.style.setProperty('--flight', flightMs + 'ms');

  for (let i = 0; i < 5; i++) {
    const $spark = document.createElement('div');
    $spark.className = 'lightning-spark';
    $spark.style.animationDelay = (i * flightMs / 7) + 'ms';
    $bolt.appendChild($spark);
  }

  document.body.appendChild($bolt);
  setTimeout(() => { if ($bolt.parentNode) $bolt.remove(); }, flightMs + 150);

  // On impact: spawn burst and signal server
  setTimeout(() => {
    // Try to get a live rect for the glow; fall back to snapshotted coords
    let tRect = null;
    if (fromTo[boltIndex].targetRef) {
      const el = findTargetElement(fromTo[boltIndex].targetRef.playerId, fromTo[boltIndex].targetRef.type, fromTo[boltIndex].targetRef.familiarIndex, lastState || state);
      if (el) tRect = el.getBoundingClientRect();
    }
    _spawnLightningImpact(to.x, to.y, tRect);
    if (isCaster) emit('bottledLightning:boltLanded', { boltIndex });
  }, flightMs);
}

function showFrozenScytheAnimations(state) {
  const events = state.frozenScytheEvents;
  if (!events || events.length === 0) return;

  for (const evt of events) {
    let el = null;
    if (evt.playerId === state.you.id) {
      if (evt.type === 'familiar') {
        const all = [...myFamLeftEls, ...myFamRightEls];
        const match = all.find(f => f.idx === evt.familiarIndex);
        if (match) el = match.el;
      }
    } else {
      if (evt.type === 'familiar') {
        el = document.querySelector(`[data-owner-id="${evt.playerId}"][data-target-type="familiar"][data-familiar-index="${evt.familiarIndex}"]`);
      }
    }
    if (!el) continue;

    const rect = el.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;

    const $container = document.createElement('div');
    $container.className = 'bomb-explosion-container frozen-scythe-anim';
    $container.style.left = cx + 'px';
    $container.style.top = cy + 'px';

    // Frost core
    const $core = document.createElement('div');
    $core.className = 'frozen-scythe-core';
    $container.appendChild($core);

    // Ice crystal shards radiating outward
    const shardCount = 10;
    const crystalChars = ['❄', '❅', '❆', '✦'];
    for (let i = 0; i < shardCount; i++) {
      const $shard = document.createElement('div');
      $shard.className = 'frozen-scythe-shard';
      const angle = (360 / shardCount) * i + (Math.random() * 18 - 9);
      const dist = 22 + Math.random() * 20;
      const rad = angle * Math.PI / 180;
      $shard.style.setProperty('--sx', (Math.cos(rad) * dist) + 'px');
      $shard.style.setProperty('--sy', (Math.sin(rad) * dist) + 'px');
      $shard.style.animationDelay = (Math.random() * 0.08) + 's';
      $shard.textContent = crystalChars[Math.floor(Math.random() * crystalChars.length)];
      $container.appendChild($shard);
    }

    document.body.appendChild($container);
    setTimeout(() => $container.remove(), 900);
  }
}

