function showBlastSaveAnimations(state) {  const events = state.blastSaveEvents;
  if (!events || events.length === 0) return;
  for (const evt of events) {
    // Find the Blast field spell card element
    const blastEl = document.querySelector(
      `[data-owner-id="${evt.blastOwnerPlayerId}"][data-field-spell-index]`
    );
    // Also try to match by name in case multiple field spells exist
    const blastEls = document.querySelectorAll(`[data-owner-id="${evt.blastOwnerPlayerId}"][data-field-spell-index]`);
    let blastTarget = null;
    for (const el of blastEls) {
      // Use first match (Death-Defying Blast is the one that fired)
      blastTarget = el; break;
    }
    const blastRect = blastTarget ? blastTarget.getBoundingClientRect() : null;
    const blastCx = blastRect ? blastRect.left + blastRect.width / 2 : window.innerWidth / 2;
    const blastCy = blastRect ? blastRect.top + blastRect.height / 2 : window.innerHeight / 2;

    for (const savedId of evt.savedPlayerIds) {
      // Find the saved student's element
      let studentEl = null;
      if (savedId === state.you.id) {
        studentEl = document.getElementById('my-student-slot');
      } else {
        studentEl = document.querySelector(`[data-owner-id="${savedId}"][data-target-type="student"]`);
      }
      if (!studentEl) continue;
      const sRect = studentEl.getBoundingClientRect();
      const sx = sRect.left + sRect.width / 2;
      const sy = sRect.top + sRect.height / 2;

      // Purple beam from student to Blast card
      const dx = blastCx - sx;
      const dy = blastCy - sy;
      const length = Math.sqrt(dx * dx + dy * dy);
      const angle = Math.atan2(dy, dx) * 180 / Math.PI;

      const $beam = document.createElement('div');
      $beam.className = 'blast-save-beam';
      $beam.style.left = sx + 'px';
      $beam.style.top = sy + 'px';
      $beam.style.width = length + 'px';
      $beam.style.transform = `rotate(${angle}deg)`;
      document.body.appendChild($beam);
      setTimeout(() => { if ($beam.parentNode) $beam.remove(); }, 1200);

      // Purple revival burst on the student
      const $burst = document.createElement('div');
      $burst.className = 'blast-save-burst';
      $burst.style.left = sx + 'px';
      $burst.style.top = sy + 'px';
      for (let i = 0; i < 10; i++) {
        const $p = document.createElement('div');
        $p.className = 'blast-save-particle';
        const angle2 = (i / 10) * Math.PI * 2;
        const dist = 25 + Math.random() * 30;
        $p.style.setProperty('--px', Math.cos(angle2) * dist + 'px');
        $p.style.setProperty('--py', Math.sin(angle2) * dist + 'px');
        $p.style.animationDelay = (0.3 + Math.random() * 0.2) + 's';
        $burst.appendChild($p);
      }
      document.body.appendChild($burst);
      setTimeout(() => { if ($burst.parentNode) $burst.remove(); }, 1600);
    }

    // Purple glow on the Blast card itself before it disappears
    if (blastTarget) {
      blastTarget.classList.add('blast-consumed');
      setTimeout(() => blastTarget.classList.remove('blast-consumed'), 1000);
    }
  }
}

