function showTCStealAnimation(state) {
  const evt = state.tcStealEvent;
  if (!evt) return;

  let el = null;
  if (evt.thiefPlayerId === state.you.id) {
    el = document.getElementById('my-familiars') || $studentSlot;
  } else {
    el = document.querySelector(`[data-owner-id="${evt.thiefPlayerId}"]`);
  }
  if (!el) return;

  const rect = el.getBoundingClientRect();

  // Dark energy vortex overlay — appended to body as fixed so it always renders above snares/cards
  const $vortex = document.createElement('div');
  $vortex.className = 'tc-steal-vortex';
  $vortex.style.position = 'fixed';
  $vortex.style.left = rect.left + 'px';
  $vortex.style.top = rect.top + 'px';
  $vortex.style.width = rect.width + 'px';
  $vortex.style.height = rect.height + 'px';
  $vortex.style.inset = '';
  document.body.appendChild($vortex);
  $vortex.addEventListener('animationend', () => $vortex.remove());
  setTimeout(() => { if ($vortex.parentNode) $vortex.remove(); }, 1200);

  // Floating label — also fixed, centred over the target area
  const $label = document.createElement('div');
  $label.className = 'tc-steal-label';
  $label.style.position = 'fixed';
  $label.style.left = (rect.left + rect.width / 2) + 'px';
  $label.style.top = (rect.top - 36) + 'px';
  $label.style.transform = 'translateX(-50%)';
  document.body.appendChild($label);
  const thiefName = evt.thiefPlayerId === state.you.id
    ? 'You'
    : (state.others.find(o => o.id === evt.thiefPlayerId)?.name || '?');
  $label.textContent = `💎 ${thiefName} steals ${evt.familiarName}!`;
  setTimeout(() => { if ($label.parentNode) $label.remove(); }, 2200);
}

