              const burstDist = 15 + Math.random() * 25;
              $spark.style.left = tx + 'px';
              $spark.style.top = ty + 'px';
              $spark.style.setProperty('--sx', (Math.cos(burstAngle) * burstDist) + 'px');
              $spark.style.setProperty('--sy', (Math.sin(burstAngle) * burstDist) + 'px');
              const colors = ['#ff2200', '#ff5500', '#ff8800', '#ffbb00', '#ffdd44'];
              $spark.style.background = colors[Math.floor(Math.random() * colors.length)];
