        $glow.style.top = toRect.top + 'px';
        $glow.style.width = toRect.width + 'px';
        $glow.style.height = toRect.height + 'px';
        document.body.appendChild($glow);
        setTimeout(() => { if ($glow.parentNode) $glow.remove(); }, 600);
