          const x = cx + Math.cos(angle) * r;
          const y = cy + Math.sin(angle) * r;
          const scale = Math.max(0.05, 1 - easeIn * 0.95);
          const opacity = t > 0.8 ? (1 - t) / 0.2 : 1;
          $c.style.left    = x + 'px';
          $c.style.top     = y + 'px';
          $c.style.transform = `translate(-50%,-50%) scale(${scale}) rotate(${angle * 180 / Math.PI}deg)`;
          $c.style.opacity = opacity;
