            $bolt.style.setProperty('--fa-flight', flightMs + 'ms');
            $bolt.style.setProperty('--fa-delay', rowDelay + 'ms');
            $bolt.style.background = `radial-gradient(circle, #fff 0%, ${colors[row % colors.length]} 50%, transparent 100%)`;
